import { Text, View } from 'react-native';

import { type useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { KangurMobileCard as Card } from '../shared/KangurMobileUi';
import { MessageCard } from './duels-primitives';
import { formatRelativeAge } from "./utils/duels-ui";
import { type UseKangurMobileDuelsLobbyResult as DuelLobbyState } from './useKangurMobileDuelsLobby';

type DuelCopy = ReturnType<typeof useKangurMobileI18n>['copy'];
type DuelLocale = ReturnType<typeof useKangurMobileI18n>['locale'];

type DuelLobbySecondarySectionProps = {
  copy: DuelCopy;
  locale: DuelLocale;
  lobby: DuelLobbyState;
};

function LeaderboardEntryRow({
  entry,
  index,
  copy,
  locale,
}: {
  entry: DuelLobbyState['leaderboardEntries'][number];
  index: number;
  copy: DuelCopy;
  locale: DuelLocale;
}): React.JSX.Element {
  return (
    <View
      key={`${entry.learnerId}-${index}`}
      style={{
        borderRadius: 20,
        borderWidth: 1,
        borderColor: '#e2e8f0',
        backgroundColor: '#f8fafc',
        padding: 14,
        gap: 8,
      }}
    >
      <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>
        #{index + 1} {entry.displayName}
      </Text>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {copy({
          de: `Siege ${entry.wins} · Niederlagen ${entry.losses} · Unentschieden ${entry.ties}`,
          en: `Wins ${entry.wins} · Losses ${entry.losses} · Draws ${entry.ties}`,
          pl: `Wygrane ${entry.wins} · Porażki ${entry.losses} · Remisy ${entry.ties}`,
        })}
      </Text>
      <Text style={{ color: '#64748b', fontSize: 12, lineHeight: 18 }}>
        {copy({
          de: `Spiele ${entry.matches} · Siegesquote ${Math.round(entry.winRate * 100)}% · letztes Spiel ${formatRelativeAge(entry.lastPlayedAt, locale)}`,
          en: `Matches ${entry.matches} · Win rate ${Math.round(entry.winRate * 100)}% · last game ${formatRelativeAge(entry.lastPlayedAt, locale)}`,
          pl: `Mecze ${entry.matches} · Win rate ${Math.round(entry.winRate * 100)}% · ostatnia gra ${formatRelativeAge(entry.lastPlayedAt, locale)}`,
        })}
      </Text>
    </View>
  );
}

function LeaderboardList({
  entries,
  copy,
  locale,
}: {
  entries: DuelLobbyState['leaderboardEntries'];
  copy: DuelCopy;
  locale: DuelLocale;
}): React.JSX.Element {
  if (entries.length === 0) {
    return (
      <MessageCard
        title={copy({
          de: 'Keine gespielten Duelle',
          en: 'No completed duels',
          pl: 'Brak rozegranych dueli',
        })}
        description={copy({
          de: 'Die Rangliste füllt sich nach den ersten abgeschlossenen Duellen.',
          en: 'The leaderboard will fill up after the first completed duels.',
          pl: 'Ranking zapełni się po pierwszych zakończonych pojedynkach.',
        })}
      />
    );
  }

  return (
    <View style={{ gap: 10 }}>
      {entries.map((entry, index) => (
        <LeaderboardEntryRow
          key={`${entry.learnerId}-${index}`}
          copy={copy}
          entry={entry}
          index={index}
          locale={locale}
        />
      ))}
    </View>
  );
}

export function DuelLobbyLeaderboardSection({
  copy,
  locale,
  lobby,
}: DuelLobbySecondarySectionProps): React.JSX.Element {
  const renderContent = (): React.JSX.Element => {
    if (lobby.leaderboardError !== null) {
      return (
        <MessageCard
          title={copy({
            de: 'Duellrangliste ist nicht verfügbar',
            en: 'Duels leaderboard is unavailable',
            pl: 'Ranking dueli jest niedostępny',
          })}
          description={lobby.leaderboardError}
          tone='error'
        />
      );
    }

    return <LeaderboardList copy={copy} entries={lobby.leaderboardEntries} locale={locale} />;
  };

  return (
    <Card>
      <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>
        {copy({
          de: 'Duellrangliste',
          en: 'Duels leaderboard',
          pl: 'Wyniki dueli',
        })}
      </Text>
      {renderContent()}
    </Card>
  );
}

import { Text, View } from 'react-native';

import { type useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { KangurMobileCard as Card } from '../shared/KangurMobileUi';
import { MessageCard } from './duels-primitives';
import { formatRelativeAge } from "./utils/duels-ui";
import { type UseKangurMobileDuelsLobbyResult as DuelLobbyState } from './useKangurMobileDuelsLobby';

type DuelCopy = ReturnType<typeof useKangurMobileI18n>['copy'];
type DuelLocale = ReturnType<typeof useKangurMobileI18n>['locale'];

type DuelLobbySecondarySectionProps = {
  copy: DuelCopy;
  locale: DuelLocale;
  lobby: DuelLobbyState;
};

function PresenceEntryRow({
  entry,
  locale,
  copy,
}: {
  entry: DuelLobbyState['presenceEntries'][number];
  locale: DuelLocale;
  copy: DuelCopy;
}): React.JSX.Element {
  return (
    <View
      style={{
        borderRadius: 20,
        borderWidth: 1,
        borderColor: '#e2e8f0',
        backgroundColor: '#f8fafc',
        padding: 14,
        gap: 6,
      }}
    >
      <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>
        {entry.displayName}
      </Text>
      <Text style={{ color: '#64748b', fontSize: 12 }}>
        {copy({
          de: 'Letzte Aktivität',
          en: 'Last activity',
          pl: 'Ostatnia aktywność',
        })}{' '}
        {formatRelativeAge(entry.lastSeenAt, locale)}
      </Text>
    </View>
  );
}

function PresenceStatus({
  lobby,
  copy,
}: {
  lobby: DuelLobbyState;
  copy: DuelCopy;
}): React.JSX.Element | null {
  if (!lobby.isAuthenticated) {
    return (
      <MessageCard
        title={copy({
          de: 'Zum aktiven Lobby-Feed anmelden',
          en: 'Sign in to see active learners',
          pl: 'Zaloguj się, aby zobaczyć aktywnych uczniów',
        })}
        description={copy({
          de: 'Nach der Anmeldung wirst du auch in der Lobby sichtbar und kannst schneller zu aktiven Rivalen zurückkehren.',
          en: 'After sign-in, you will also become visible in the lobby and can return to active rivals faster.',
          pl: 'Po zalogowaniu będziesz też widoczny w lobby i szybciej wrócisz do aktywnych rywali.',
        })}
      />
    );
  }

  if (lobby.presenceError !== null) {
    return (
      <MessageCard
        title={copy({
          de: 'Präsenz konnte nicht geladen werden',
          en: 'Could not load presence',
          pl: 'Nie udało się pobrać obecności',
        })}
        description={lobby.presenceError}
        tone='error'
      />
    );
  }

  if (lobby.isPresenceLoading) {
    return (
      <MessageCard
        title={copy({
          de: 'Präsenz wird aktualisiert',
          en: 'Updating presence',
          pl: 'Aktualizujemy obecność',
        })}
        description={copy({
          de: 'Die Liste der in der Lobby sichtbaren Lernenden wird synchronisiert.',
          en: 'Synchronizing the list of learners visible in the lobby.',
          pl: 'Synchronizujemy listę uczniów widocznych w lobby.',
        })}
      />
    );
  }

  return null;
}

export function DuelLobbyPresenceSection({
  copy,
  locale,
  lobby,
}: DuelLobbySecondarySectionProps): React.JSX.Element {
  const renderContent = (): React.JSX.Element => {
    const status = PresenceStatus({ lobby, copy });
    if (status !== null) {
      return status;
    }

    if (lobby.presenceEntries.length === 0) {
      return (
        <MessageCard
          title={copy({
            de: 'Keine aktiven Lernenden',
            en: 'No active learners',
            pl: 'Brak obecnych uczniów',
          })}
          description={copy({
            de: 'Wenn andere Lernende die Lobby öffnen, erscheinen sie hier.',
            en: 'When other learners open the lobby, they will appear here.',
            pl: 'Gdy inni uczniowie otworzą lobby, pojawią się tutaj.',
          })}
        />
      );
    }

    return (
      <View style={{ gap: 10 }}>
        {lobby.presenceEntries.map((entry) => (
          <PresenceEntryRow key={entry.learnerId} copy={copy} entry={entry} locale={locale} />
        ))}
      </View>
    );
  };

  return (
    <Card>
      <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>
        {copy({
          de: 'Aktive Lernende',
          en: 'Active learners',
          pl: 'Aktywni uczniowie',
        })}
      </Text>
      {renderContent()}
    </Card>
  );
}

import { Text, View } from 'react-native';

import { type useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { KangurMobileCard as Card } from '../shared/KangurMobileUi';
import { ActionButton, MessageCard } from './duels-primitives';
import { formatRelativeAge } from "./utils/duels-ui";
import { type UseKangurMobileDuelsLobbyResult as DuelLobbyState } from './useKangurMobileDuelsLobby';

type DuelCopy = ReturnType<typeof useKangurMobileI18n>['copy'];
type DuelLocale = ReturnType<typeof useKangurMobileI18n>['locale'];

type DuelLobbyRecentOpponentsSectionProps = {
  copy: DuelCopy;
  locale: DuelLocale;
  lobby: DuelLobbyState;
  onOpenSession: (sessionId: string) => void;
};

function OpponentEntryRow({
  entry,
  copy,
  locale,
  isActionPending,
  onOpenSession,
  createPrivateChallenge,
}: {
  entry: DuelLobbyState['opponents'][number];
  copy: DuelCopy;
  locale: DuelLocale;
  isActionPending: boolean;
  onOpenSession: (sessionId: string) => void;
  createPrivateChallenge: DuelLobbyState['createPrivateChallenge'];
}): React.JSX.Element {
  return (
    <View
      style={{
        borderRadius: 20,
        borderWidth: 1,
        borderColor: '#e2e8f0',
        backgroundColor: '#f8fafc',
        padding: 14,
        gap: 8,
      }}
    >
      <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>
        {entry.displayName}
      </Text>
      <Text style={{ color: '#64748b', fontSize: 12 }}>
        {copy({
          de: 'Letztes Spiel',
          en: 'Last game',
          pl: 'Ostatnia gra',
        })}{' '}
        {formatRelativeAge(entry.lastPlayedAt, locale)}
      </Text>
      <ActionButton
        disabled={isActionPending}
        label={copy({
          de: 'Erneut herausfordern',
          en: 'Challenge again',
          pl: 'Wyzwij ponownie',
        })}
        onPress={async () => {
          const nextSessionId = await createPrivateChallenge(entry.learnerId);
          if (nextSessionId !== null) {
            onOpenSession(nextSessionId);
          }
        }}
        stretch
      />
    </View>
  );
}

function OpponentsStatus({
  lobby,
  copy,
}: {
  lobby: DuelLobbyState;
  copy: DuelCopy;
}): React.JSX.Element | null {
  if (!lobby.isAuthenticated) {
    return (
      <MessageCard
        title={copy({
          de: 'Letzte Rivalen erfordern Anmeldung',
          en: 'Recent rivals require sign-in',
          pl: 'Ostatni rywale wymagają logowania',
        })}
        description={copy({
          de: 'Nach der Anmeldung erscheinen hier die letzten Rivalen und schnelle Rückkämpfe.',
          en: 'After signing in, recent rivals and quick rematches will appear here.',
          pl: 'Po zalogowaniu pojawią się tutaj ostatni rywale i szybkie rewanże.',
        })}
      />
    );
  }

  if (lobby.isOpponentsLoading) {
    return (
      <MessageCard
        title={copy({
          de: 'Gegnerliste wird geladen',
          en: 'Loading opponents',
          pl: 'Ładujemy listę przeciwników',
        })}
        description={copy({
          de: 'Die letzten Rivalen aus wcześniejszych Duellen werden geladen.',
          en: 'Loading recent rivals from earlier duels.',
          pl: 'Pobieramy ostatnich rywali z wcześniejszych pojedynków.',
        })}
      />
    );
  }

  return null;
}

function RecentOpponentsContent({
  lobby,
  copy,
  locale,
  onOpenSession,
}: {
  lobby: DuelLobbyState;
  copy: DuelCopy;
  locale: DuelLocale;
  onOpenSession: (sessionId: string) => void;
}): React.JSX.Element {
  const status = OpponentsStatus({ lobby, copy });
  if (status !== null) {
    return status;
  }

  if (lobby.opponents.length === 0) {
    return (
      <MessageCard
        title={copy({
          de: 'Noch keine letzten Rivalen',
          en: 'No recent rivals yet',
          pl: 'Brak jeszcze ostatnich rywali',
        })}
        description={copy({
          de: 'Beende das erste Duell, damit sich diese Liste automatisch füllt.',
          en: 'Finish the first duel and this list will fill automatically.',
          pl: 'Rozegraj pierwszy pojedynek, aby ta lista wypełniła się automatycznie.',
        })}
      />
    );
  }

  return (
    <View style={{ gap: 10 }}>
      {lobby.opponents.map((entry) => (
        <OpponentEntryRow
          key={entry.learnerId}
          copy={copy}
          createPrivateChallenge={lobby.createPrivateChallenge}
          entry={entry}
          isActionPending={lobby.isActionPending}
          locale={locale}
          onOpenSession={onOpenSession}
        />
      ))}
    </View>
  );
}

export function DuelLobbyRecentOpponentsSection({
  copy,
  locale,
  lobby,
  onOpenSession,
}: DuelLobbyRecentOpponentsSectionProps): React.JSX.Element {
  return (
    <Card>
      <View style={{ gap: 8 }}>
        <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>
          {copy({
            de: 'Letzte Gegner',
            en: 'Recent opponents',
            pl: 'Ostatni przeciwnicy',
          })}
        </Text>
        {lobby.isAuthenticated ? (
          <ActionButton
            disabled={lobby.isOpponentsLoading}
            label={copy({
              de: 'Gegnerliste aktualisieren',
              en: 'Refresh opponents',
              pl: 'Odśwież przeciwników',
            })}
            onPress={lobby.refresh}
            stretch
            tone='secondary'
          />
        ) : null}
      </View>
      <RecentOpponentsContent
        copy={copy}
        lobby={lobby}
        locale={locale}
        onOpenSession={onOpenSession}
      />
    </Card>
  );
}

import { Text, View } from 'react-native';
import { type useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { KangurMobileCard as Card, KangurMobileFilterChip } from '../shared/KangurMobileUi';
import { ActionButton, AutoRefreshChip, LobbyEntryCard, MessageCard } from './duels-primitives';
import { type KangurDuelLobbyEntry } from '@kangur/contracts/kangur-duels';
import { type UseKangurMobileDuelsLobbyResult as DuelLobbyState } from './useKangurMobileDuelsLobby';
import {
  MODE_FILTER_OPTIONS,
  formatModeLabel,
  formatOperationLabel,
  formatStatusLabel,
  localizeDuelText,
} from './utils/duels-ui';
import { type KangurMobileLocalizedValue } from '../i18n/kangurMobileI18n';

type DuelCopy = ReturnType<typeof useKangurMobileI18n>['copy'];
type DuelLocale = ReturnType<typeof useKangurMobileI18n>['locale'];
type PublicEntry = KangurDuelLobbyEntry;
type InviteEntry = KangurDuelLobbyEntry;

type DuelLobbyRoomsPanelProps = {
  autoRefreshChipLabel: string;
  autoRefreshEnabled: boolean;
  copy: DuelCopy;
  lobby: DuelLobbyState;
  locale: DuelLocale;
  onToggleAutoRefresh: () => void;
  renderJoinAction: (targetSessionId: string) => React.JSX.Element;
  renderSpectateAction: (targetSessionId: string) => React.JSX.Element;
};

const LobbyHeader = ({ copy, lobby, autoRefreshEnabled, autoRefreshChipLabel, onToggleAutoRefresh }: Pick<DuelLobbyRoomsPanelProps, 'copy' | 'lobby' | 'autoRefreshEnabled' | 'autoRefreshChipLabel' | 'onToggleAutoRefresh'>): React.JSX.Element => (
  <View style={{ gap: 12 }}>
    <View style={{ gap: 4 }}>
      <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>{copy({ de: 'Lobby', en: 'Lobby', pl: 'Lobby' })}</Text>
      <Text style={{ color: '#64748b', fontSize: 13 }}>{copy({ de: `Sichtbare öffentliche Räume: ${lobby.visiblePublicEntries.length}`, en: `Visible public rooms: ${lobby.visiblePublicEntries.length}`, pl: `Widoczne publiczne pokoje: ${lobby.visiblePublicEntries.length}` })}</Text>
    </View>
    <View style={{ gap: 8, alignItems: 'stretch' }}>
      <ActionButton disabled={lobby.isActionPending} label={copy({ de: 'Aktualisieren', en: 'Refresh', pl: 'Odśwież' })} onPress={lobby.refresh} stretch tone='secondary' />
      <AutoRefreshChip enabled={autoRefreshEnabled} label={autoRefreshChipLabel} onToggle={onToggleAutoRefresh} fullWidth />
    </View>
  </View>
);

const InviteEntriesList = ({ lobby, renderJoinAction, locale, copy }: Pick<DuelLobbyRoomsPanelProps, 'lobby' | 'renderJoinAction' | 'locale' | 'copy'>): React.JSX.Element => (
  <View style={{ gap: 10 }}>
    <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>{copy({ de: 'Einladungen', en: 'Invites', pl: 'Zaproszenia' })}</Text>
    {lobby.inviteEntries.map((entry: InviteEntry) => (
      <LobbyEntryCard key={entry.sessionId} action={renderJoinAction(entry.sessionId)} actionLabel={copy({ de: 'Private Einladung für angemeldete Lernende.', en: 'Private invite for a signed-in learner.', pl: 'Prywatne zaproszenie dla zalogowanego ucznia.' })} description={copy({ de: `Gastgeber ${entry.host.displayName} lädt zu einem privaten Duell ${formatOperationLabel(entry.operation, locale)} ein.`, en: `Host ${entry.host.displayName} is inviting you to a private ${formatOperationLabel(entry.operation, locale)} duel.`, pl: `Gospodarz ${entry.host.displayName} zaprasza do prywatnego pojedynku ${formatOperationLabel(entry.operation, locale)}.` })} entry={entry} locale={locale} />
    ))}
  </View>
);

const PublicEntryRow = ({ entry, renderJoinAction, renderSpectateAction, locale, copy }: { entry: PublicEntry; renderJoinAction: (sessionId: string) => React.JSX.Element; renderSpectateAction: (sessionId: string) => React.JSX.Element; locale: DuelLocale; copy: DuelCopy }): React.JSX.Element => {
  const modeLabel = formatModeLabel(entry.mode, locale) as string;
  const statusLabel = (formatStatusLabel(entry.status, locale) as string).toLowerCase();
  const desc = copy({ de: `${modeLabel} von ${entry.host.displayName}. Status: ${statusLabel}.`, en: `${modeLabel} hosted by ${entry.host.displayName}. Status: ${statusLabel}.`, pl: `${modeLabel} gospodarza ${entry.host.displayName}. Status: ${statusLabel}.` });
  return (
    <LobbyEntryCard action={<View style={{ gap: 8 }}>{renderJoinAction(entry.sessionId)}{renderSpectateAction(entry.sessionId)}</View>} actionLabel={copy({ de: 'Du kannst als Spieler beitreten oder den Raum im Zuschauermodus öffnen.', en: 'You can join as a player or open the room in spectator mode.', pl: 'Możesz dołączyć jako gracz albo otworzyć pokój w trybie obserwatora.' })} description={desc} entry={entry} locale={locale} />
  );
};

const PublicEntriesList = ({ lobby, renderJoinAction, renderSpectateAction, locale, copy }: Pick<DuelLobbyRoomsPanelProps, 'lobby' | 'renderJoinAction' | 'renderSpectateAction' | 'locale' | 'copy'>): React.JSX.Element => lobby.visiblePublicEntries.length === 0 ? (
  <MessageCard title={copy({ de: 'Keine öffentlichen Duelle', en: 'No public duels', pl: 'Brak publicznych pojedynków' })} description={copy({ de: 'Ein anderer Filter oder ein schnelles Match erstellt einen neuen Raum zum Beitreten.', en: 'Changing the filter or starting a quick match will create a new room to join.', pl: 'Zmiana filtra albo szybki mecz utworzy nowy pokój gotowy do dołączenia.' })} />
) : (
  <View style={{ gap: 10 }}>
    <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>{copy({ de: 'Öffentliche Räume', en: 'Public rooms', pl: 'Publiczne pokoje' })}</Text>
    {lobby.visiblePublicEntries.map((entry: PublicEntry) => <PublicEntryRow key={entry.sessionId} copy={copy} entry={entry} locale={locale} renderJoinAction={renderJoinAction} renderSpectateAction={renderSpectateAction} />)}
  </View>
);

const RoomsContent = ({ lobby, copy, locale, renderJoinAction, renderSpectateAction }: Pick<DuelLobbyRoomsPanelProps, 'lobby' | 'copy' | 'locale' | 'renderJoinAction' | 'renderSpectateAction'>): React.JSX.Element => (
  <>
    {lobby.inviteEntries.length > 0 && <InviteEntriesList copy={copy} locale={locale} lobby={lobby} renderJoinAction={renderJoinAction} />}
    <PublicEntriesList copy={copy} locale={locale} lobby={lobby} renderJoinAction={renderJoinAction} renderSpectateAction={renderSpectateAction} />
  </>
);

export function DuelLobbyRoomsPanel({ autoRefreshChipLabel, autoRefreshEnabled, copy, lobby, locale, onToggleAutoRefresh, renderJoinAction, renderSpectateAction }: DuelLobbyRoomsPanelProps): React.JSX.Element {
  const renderLobbyStatus = (currentLobby: DuelLobbyState): React.JSX.Element | null => {
    if (typeof currentLobby.lobbyError === 'string') return <MessageCard title={copy({ de: 'Lobby ist nicht verfügbar', en: 'Lobby is unavailable', pl: 'Lobby jest niedostępne' })} description={currentLobby.lobbyError} tone='error' />;
    if (currentLobby.isLobbyLoading) return <MessageCard title={copy({ de: 'Lobby wird geladen', en: 'Loading lobby', pl: 'Ładujemy lobby' })} description={currentLobby.isRestoringAuth ? copy({ de: 'Die Anmeldung wird wiederhergestellt und verfügbare Duelle werden geladen.', en: 'Restoring sign-in and loading available duels.', pl: 'Przywracamy logowanie i pobieramy dostępne pojedynki.' }) : copy({ de: 'Verfügbare öffentliche und private Räume werden geladen.', en: 'Loading available public and private rooms.', pl: 'Pobieramy dostępne publiczne i prywatne pokoje.' })} />;
    return null;
  };

  const status = renderLobbyStatus(lobby);
  return (
    <Card>
      <LobbyHeader autoRefreshChipLabel={autoRefreshChipLabel} autoRefreshEnabled={autoRefreshEnabled} copy={copy} lobby={lobby} onToggleAutoRefresh={onToggleAutoRefresh} />
      <View style={{ flexDirection: 'column', gap: 8 }}>
        {MODE_FILTER_OPTIONS.map((option: { value: 'all' | 'challenge' | 'quick_match'; label: KangurMobileLocalizedValue<string> }) => (
          <KangurMobileFilterChip
            fullWidth
            key={option.value}
            label={localizeDuelText(option.label, locale)}
            onPress={() => lobby.setModeFilter(option.value)}
            selected={lobby.modeFilter === option.value}
          />
        ))}
      </View>
      {status ?? <RoomsContent copy={copy} locale={locale} lobby={lobby} renderJoinAction={renderJoinAction} renderSpectateAction={renderSpectateAction} />}
    </Card>
  );
}

import { type UseKangurMobileDuelSessionResult as DuelSessionState } from './useKangurMobileDuelSession';
import { type DuelCopy, type DuelLocale, type DuelRoundProgress } from './duels-screen-session-view';
import { KangurMobileCard as Card } from '../shared/KangurMobileUi';
import { DetailsBody } from './components/DetailsBody';

export type DuelSessionDetailsCardProps = {
  copy: DuelCopy;
  duel: DuelSessionState;
  hasWaitingSession: boolean;
  locale: DuelLocale;
  roundProgress: DuelRoundProgress;
  sessionTimelineItems: string[];
};

export function DuelSessionDetailsCard({
  copy,
  duel,
  hasWaitingSession,
  locale,
  roundProgress,
  sessionTimelineItems,
}: DuelSessionDetailsCardProps): React.JSX.Element {
  const session = duel.session;
  if (session === null) return <></>;
  return (
    <Card>
      <DetailsBody
        copy={copy}
        duel={duel}
        hasWaitingSession={hasWaitingSession}
        locale={locale}
        roundProgress={roundProgress}
        session={session}
        sessionTimelineItems={sessionTimelineItems}
      />
    </Card>
  );
}

import { View } from 'react-native';
import {
  BadgesCard,
