export function resolveSessionIdParam(value: string | string[] | undefined): string | null {
  const raw = Array.isArray(value) ? value[0] : value;
  const normalized = typeof raw === 'string' ? raw.trim() : '';
  return isStringNotEmpty(normalized) ? normalized : null;
}

export function resolveSpectateParam(value: string | string[] | undefined): boolean {
  const raw = Array.isArray(value) ? value[0] : value;
  const normalized = typeof raw === 'string' ? raw.trim().toLowerCase() : '';
  return normalized === '1' || normalized === 'true' || normalized === 'yes';
}

import type { Href } from 'expo-router';

type CreateKangurDuelsHrefOptions = {
  joinSessionId?: string | null;
  sessionId?: string | null;
  spectate?: boolean;
};

export const createKangurDuelsHref = (
  options: CreateKangurDuelsHrefOptions = {},
): Href => {
  const joinSessionId = options.joinSessionId?.trim() ?? '';
  const sessionId = options.sessionId?.trim() ?? '';
  const spectate = options.spectate === true;

  if (sessionId) {
    return ({
      pathname: '/duels',
      params: {
        sessionId,
        ...(spectate ? { spectate: '1' } : {}),
      },
    }) as unknown as Href;
  }

  if (joinSessionId) {
    return ({
      pathname: '/duels',
      params: {
        join: joinSessionId,
      },
    }) as unknown as Href;
  }

  return '/duels' as Href;
};

import { useEffect } from 'react';
import { AUTO_REFRESH_INTERVAL_MS } from "./utils/duels-ui";
import { safeSetInterval, safeClearInterval } from '@/shared/lib/timers';
import type { UseKangurMobileDuelsLobbyResult } from './useKangurMobileDuelsLobby';

export function useKangurDuelsAutoRefresh(
  lobby: UseKangurMobileDuelsLobbyResult,
  enabled: boolean,
) {
  useEffect(() => {
    if (!enabled) return undefined;

    const handleLobbyRefresh = (): void => {
      void lobby.refresh();
    };

    handleLobbyRefresh();
    const intervalId = safeSetInterval(handleLobbyRefresh, AUTO_REFRESH_INTERVAL_MS);

    return () => {
      safeClearInterval(intervalId);
    };
  }, [enabled, lobby.refresh]);
}

import { useState } from 'react';
import type { UseKangurMobileDuelLobbyChatResult } from './useKangurMobileDuelLobbyChat';
import type { KangurMobileLocalizedValue } from '../i18n/kangurMobileI18n';

type DuelCopy = (value: KangurMobileLocalizedValue<string>) => string;

export function useKangurDuelsLobbyActions(
  chat: UseKangurMobileDuelLobbyChatResult,
  copy: DuelCopy,
) {
  const [chatDraft, setChatDraft] = useState('');
  const [chatActionError, setChatActionError] = useState<string | null>(null);
  const [autoRefreshEnabled, setAutoRefreshEnabled] = useState(true);

  const handleLobbyChatSend = async (): Promise<void> => {
    setChatActionError(null);

    const didSend = await chat.sendMessage(chatDraft);
    if (didSend) {
      setChatDraft('');
      return;
    }

    setChatActionError(
      copy({
        de: 'Die Nachricht konnte nicht in den Lobby-Chat gesendet werden.',
        en: 'Could not send the message to the lobby chat.',
        pl: 'Nie udało się wysłać wiadomości do czatu lobby.',
      }),
    );
  };

  return {
    chatDraft,
    setChatDraft,
    chatActionError,
    setChatActionError,
    autoRefreshEnabled,
    setAutoRefreshEnabled,
    handleLobbyChatSend,
  };
}

import { useState, useRef, useEffect, useCallback } from 'react';
import type { UseKangurMobileDuelsLobbyResult } from './useKangurMobileDuelsLobby';
import type { KangurMobileLocalizedValue } from '../i18n/kangurMobileI18n';

type DuelCopy = (value: KangurMobileLocalizedValue<string>) => string;

export function useKangurDuelsRouteJoin(
  lobby: UseKangurMobileDuelsLobbyResult,
  joinSessionId: string | null,
  routeSessionId: string | null,
  isSpectatingRoute: boolean,
  copy: DuelCopy,
  openSession: (id: string) => void,
) {
  const [routeJoinError, setRouteJoinError] = useState<string | null>(null);
  const [isJoiningFromRoute, setIsJoiningFromRoute] = useState(false);
  const attemptedJoinSessionIdRef = useRef<string | null>(null);

  const joinSessionFromRoute = useCallback(async (): Promise<void> => {
    if (joinSessionId === null) return;

    setRouteJoinError(null);
    setIsJoiningFromRoute(true);

    try {
      const nextSessionId = await lobby.joinDuel(joinSessionId);
      if (nextSessionId !== null) {
        openSession(nextSessionId);
        return;
      }

      setRouteJoinError(
        lobby.actionError ??
          copy({
            de: 'Der Duell-Einladung konnte nicht beigetreten werden.',
            en: 'Could not join the duel invite.',
            pl: 'Nie udało się dołączyć do zaproszenia do pojedynku.',
          }),
      );
    } finally {
      setIsJoiningFromRoute(false);
    }
  }, [joinSessionId, lobby, openSession, copy]);

  useEffect(() => {
    if (joinSessionId === null || routeSessionId !== null || isSpectatingRoute) return;
    if (!lobby.isAuthenticated || lobby.isLoadingAuth) return;
    if (attemptedJoinSessionIdRef.current === joinSessionId) return;

    attemptedJoinSessionIdRef.current = joinSessionId;
    void joinSessionFromRoute();
  }, [isSpectatingRoute, joinSessionId, lobby.isAuthenticated, lobby.isLoadingAuth, routeSessionId, joinSessionFromRoute]);

  return {
    routeJoinError,
    isJoiningFromRoute,
    joinSessionFromRoute,
  };
}

