  searchStatusLabel: string;
  searchStatusTone: KangurMobileTone;
  sessionState: UseKangurDuelsSessionStateResult;
};

function createDuelsScreenData(
  copy: ReturnType<typeof useKangurMobileI18n>['copy'],
  locale: ReturnType<typeof useKangurMobileI18n>['locale'],
  router: ReturnType<typeof useRouter>,
  auth: ReturnType<typeof useKangurMobileAuth>,
  lobby: UseKangurMobileDuelsLobbyResult,
  chat: UseKangurMobileDuelLobbyChatResult,
  duel: UseKangurMobileDuelSessionResult,
  sessionState: UseKangurDuelsSessionStateResult,
  routeSessionId: string | null,
  joinSessionId: string | null,
  isSpectatingRoute: boolean,
): KangurDuelsScreenData {
  const activeLearnerId = auth.session.user?.activeLearner?.id ?? auth.session.user?.id ?? null;
  const openSession = (id: string) => router.replace(createKangurDuelsHref({ sessionId: id }));
  const openLobby = () => router.replace(createKangurDuelsHref());
  const lobbyActions = useKangurDuelsLobbyActions(chat, copy);
  const sessionActions = useKangurDuelsSessionActions(duel, lobby, locale, copy, activeLearnerId, openSession);
  const routeJoin = useKangurDuelsRouteJoin(lobby, joinSessionId, routeSessionId, isSpectatingRoute, copy, openSession);
  const { searchStatusLabel, searchStatusTone } = useKangurDuelsSearchStatus(copy, lobby);
  const joinDuelAction = async (id: string) => {
    const next = await lobby.joinDuel(id);
    if (next) openSession(next);
  };
  return {
    copy, locale, router,
    isLoadingAuth: auth.isLoadingAuth,
    signIn: auth.signIn,
    supportsLearnerCredentials: auth.supportsLearnerCredentials,
    routeSessionId, joinSessionId, sessionId: routeSessionId, isSpectatingRoute,
    lobby, chat, duel, activeLearnerId, openSession, openLobby,
    lobbyActions, sessionActions, routeJoin, joinDuelAction,
    searchStatusLabel, searchStatusTone, sessionState,
  };
}

export function useKangurDuelsScreenData(): KangurDuelsScreenData {
  const { copy, locale } = useKangurMobileI18n();
  const params = useLocalSearchParams<{ join?: string; spectate?: string; sessionId?: string }>();
  const router = useRouter();
  const auth = useKangurMobileAuth();

  const routeSessionId = resolveSessionIdParam(params.sessionId ?? null);
  const joinSessionId = routeSessionId !== null ? null : resolveSessionIdParam(params.join ?? null);
  const isSpectatingRoute = resolveSpectateParam(params.spectate ?? null);

  const lobby = useKangurMobileDuelsLobby();
  const chat = useKangurMobileDuelLobbyChat();
  const duel = useKangurMobileDuelSession(routeSessionId, { spectate: isSpectatingRoute });
  const sessionState = useKangurDuelsSessionState(copy, locale, duel);

  return createDuelsScreenData(
    copy, locale, router, auth, lobby, chat, duel, sessionState,
    routeSessionId, joinSessionId, isSpectatingRoute
  );
}

import { useState } from 'react';
import { shareKangurDuelInvite } from './duelInviteShare';
import { normalizeSeriesBestOf } from "./utils/duels-ui";
import type { UseKangurMobileDuelSessionResult } from './useKangurMobileDuelSession';
import type { UseKangurMobileDuelsLobbyResult } from './useKangurMobileDuelsLobby';
import type { KangurMobileLocale, KangurMobileLocalizedValue } from '../i18n/kangurMobileI18n';

type DuelCopy = (value: KangurMobileLocalizedValue<string>) => string;

export function useKangurDuelsSessionActions(
  duel: UseKangurMobileDuelSessionResult,
  lobby: UseKangurMobileDuelsLobbyResult,
  locale: KangurMobileLocale,
  copy: DuelCopy,
  activeLearnerId: string | null,
  openSession: (id: string) => void,
) {
  const [inviteShareError, setInviteShareError] = useState<string | null>(null);

  const handleRematch = async (): Promise<void> => {
    if (duel.session === null || duel.isSpectating) return;

    const nextSeriesBestOf = normalizeSeriesBestOf(duel.session.series?.bestOf);
    const overrides = {
      difficulty: duel.session.difficulty,
      operation: duel.session.operation,
      seriesBestOf: nextSeriesBestOf,
    } as const;

    if (duel.session.visibility === 'private') {
      const opponentLearnerId =
        duel.session.players.find((player) => player.learnerId !== activeLearnerId)
          ?.learnerId ?? null;

      if (opponentLearnerId !== null) {
        const nextSessionId = await lobby.createPrivateChallenge(opponentLearnerId, overrides);
        if (nextSessionId !== null) openSession(nextSessionId);
      }
      return;
    }

    const nextSessionId =
      duel.session.mode === 'quick_match'
        ? await lobby.createQuickMatch(overrides)
        : await lobby.createPublicChallenge(overrides);
    if (nextSessionId !== null) openSession(nextSessionId);
  };

  const handleInviteShare = async (): Promise<void> => {
    if (duel.session === null || duel.player === null || duel.isSpectating) return;

    setInviteShareError(null);
    try {
      await shareKangurDuelInvite({
        locale,
        sessionId: duel.session.id,
        sharerDisplayName: duel.player.displayName,
      });
    } catch (error) {
      setInviteShareError(
        error instanceof Error && error.message.trim().length > 0
          ? error.message
          : copy({
              de: 'Der Einladungslink konnte nicht geteilt werden.',
              en: 'Could not share the invite link.',
              pl: 'Nie udało się udostępnić linku do zaproszenia.',
            }),
      );
    }
  };

  return {
    inviteShareError,
    setInviteShareError,
    handleRematch,
    handleInviteShare,
  };
}

import { type useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { formatKangurMobileScoreDateTime } from '../scores/mobileScoreSummary';
import { type UseKangurMobileDuelSessionResult as DuelSessionState } from './useKangurMobileDuelSession';
import {
  isWaitingSessionStatus,
  resolveRoundProgress
} from "./utils/duels-ui";

type DuelCopy = ReturnType<typeof useKangurMobileI18n>['copy'];
type DuelLocale = ReturnType<typeof useKangurMobileI18n>['locale'];

function getInviteeName(duel: DuelSessionState, copy: DuelCopy): string {
  const rawInviteeName = duel.session?.invitedLearnerName?.trim();
  if (typeof rawInviteeName === 'string' && rawInviteeName !== '') {
    return rawInviteeName;
  }
  return copy({
    de: 'der zweiten Person',
    en: 'the other player',
    pl: 'drugiej osoby',
  });
}

function getSessionTimelineItems(
  duel: DuelSessionState,
  copy: DuelCopy,
  locale: DuelLocale,
): string[] {
  const items: string[] = [];
  if (duel.session === null) {
    return items;
  }

  items.push(
    copy({
      de: `Erstellt ${formatKangurMobileScoreDateTime(duel.session.createdAt, locale)}`,
      en: `Created ${formatKangurMobileScoreDateTime(duel.session.createdAt, locale)}`,
      pl: `Utworzono ${formatKangurMobileScoreDateTime(duel.session.createdAt, locale)}`,
    }),
  );
  if (duel.session.startedAt !== null) {
    items.push(
      copy({
        de: `Gestartet ${formatKangurMobileScoreDateTime(duel.session.startedAt, locale)}`,
        en: `Started ${formatKangurMobileScoreDateTime(duel.session.startedAt, locale)}`,
        pl: `Rozpoczęto ${formatKangurMobileScoreDateTime(duel.session.startedAt, locale)}`,
      }),
    );
  }
  items.push(
    copy({
      de: `Zuletzt aktualisiert ${formatKangurMobileScoreDateTime(duel.session.updatedAt, locale)}`,
      en: `Last updated ${formatKangurMobileScoreDateTime(duel.session.updatedAt, locale)}`,
      pl: `Ostatnia aktualizacja ${formatKangurMobileScoreDateTime(duel.session.updatedAt, locale)}`,
    }),
  );
  if (duel.session.endedAt !== null) {
    items.push(
      copy({
        de: `Beendet ${formatKangurMobileScoreDateTime(duel.session.endedAt, locale)}`,
        en: `Ended ${formatKangurMobileScoreDateTime(duel.session.endedAt, locale)}`,
        pl: `Zakończenie ${formatKangurMobileScoreDateTime(duel.session.endedAt, locale)}`,
      }),
    );
  }
  return items;
}

export type UseKangurDuelsSessionStateResult = {
  activePlayersCount: number;
  canShareInvite: boolean;
  hasPendingInvitedPlayer: boolean;
  hasWaitingSession: boolean;
  inviteeName: string;
  isFinishedSession: boolean;
  isInvitedLearnerMissing: boolean;
  needsMorePlayersToStart: boolean;
  roundProgress: {
    total: number;
    current: number;
    percent: number;
  } | null;
  sessionTimelineItems: string[];
};

export function useKangurDuelsSessionState(
  copy: DuelCopy,
  locale: DuelLocale,
  duel: DuelSessionState,
): UseKangurDuelsSessionStateResult {
  const hasWaitingSession = duel.session !== null && isWaitingSessionStatus(duel.session.status);
  const isFinishedSession = duel.session !== null && (duel.session.status === 'completed' || duel.session.status === 'aborted');
  const roundProgress = duel.session !== null
    ? resolveRoundProgress(duel.session, duel.player, duel.isSpectating)
    : null;
  const activePlayersCount =
    duel.session?.players.filter((player) => player.status !== 'left').length ?? 0;
  const hasPendingInvitedPlayer =
    duel.session?.players.some((player) => player.status === 'invited') ?? false;

  let isInvitedLearnerMissing = false;
  if (duel.session?.invitedLearnerId !== null && duel.session?.invitedLearnerId !== undefined) {
    const invitedId = duel.session.invitedLearnerId;
    isInvitedLearnerMissing = !duel.session.players.some(
      (p) => p.learnerId === invitedId && p.status !== 'left',
    );
  }

  const needsMorePlayersToStart = duel.session !== null && activePlayersCount < (duel.session.minPlayersToStart ?? 2);
  const canShareInvite = Boolean(
    duel.session !== null &&
      duel.player !== null &&
      !duel.isSpectating &&
      duel.session.visibility === 'private' &&
      hasWaitingSession &&
      (hasPendingInvitedPlayer || isInvitedLearnerMissing || needsMorePlayersToStart),
  );

  return {
    activePlayersCount,
    canShareInvite,
    hasPendingInvitedPlayer,
    hasWaitingSession,
    inviteeName: getInviteeName(duel, copy),
    isFinishedSession,
    isInvitedLearnerMissing,
    needsMorePlayersToStart,
    roundProgress,
    sessionTimelineItems: getSessionTimelineItems(duel, copy, locale),
  };
}

import type { KangurDuelLobbyChatListResponse, KangurDuelLobbyChatMessage } from '@kangur/contracts/kangur-duels-chat';
import { KANGUR_DUELS_LOBBY_CHAT_DEFAULT_LIMIT, KANGUR_DUELS_LOBBY_CHAT_MAX_MESSAGE_LENGTH } from '@kangur/contracts/kangur-duels-chat';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { useState } from 'react';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import {
  useKangurMobileI18n,
} from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import { resolveMobileDuelErrorMessage } from './mobileDuelErrorMessages';

const MOBILE_DUEL_CHAT_POLL_MS = 12_000;

export type UseKangurMobileDuelLobbyChatResult = {
  error: string | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  isRestoringAuth: boolean;
  isSending: boolean;
  maxMessageLength: number;
  messages: KangurDuelLobbyChatMessage[];
  refresh: () => Promise<void>;
  sendMessage: (message: string) => Promise<boolean>;
};

const appendMessage = (
  current: KangurDuelLobbyChatListResponse | undefined,
  incoming: KangurDuelLobbyChatMessage,
): KangurDuelLobbyChatListResponse => {
  const existingMessages = current?.messages ?? [];
  const deduped = existingMessages.filter((message) => message.id !== incoming.id);

  return {
    messages: [...deduped, incoming].sort((left, right) =>
      left.createdAt.localeCompare(right.createdAt),
    ),
    nextCursor: current?.nextCursor ?? null,
    serverTime: current?.serverTime ?? incoming.createdAt,
  };
};

export const useKangurMobileDuelLobbyChat =
  (): UseKangurMobileDuelLobbyChatResult => {
    const { copy } = useKangurMobileI18n();
    const queryClient = useQueryClient();
    const { apiBaseUrl, apiClient } = useKangurMobileRuntime();
    const { isLoadingAuth, session } = useKangurMobileAuth();
    const [isSending, setIsSending] = useState(false);
    const learnerIdentity =
      session.user?.activeLearner?.id ??
      session.user?.email ??
      session.user?.id ??
      'guest';
    const isAuthenticated = session.status === 'authenticated';
    const isRestoringAuth = isLoadingAuth && !isAuthenticated;
    const queryKey = [
      'kangur-mobile',
      'duels',
      'lobby-chat',
      apiBaseUrl,
      learnerIdentity,
    ] as const;

    const chatQuery = useQuery({
      enabled: isAuthenticated,
      queryKey,
      queryFn: async () =>
        apiClient.listDuelLobbyChat(
          { limit: KANGUR_DUELS_LOBBY_CHAT_DEFAULT_LIMIT },
          { cache: 'no-store' },
        ),
      refetchInterval: MOBILE_DUEL_CHAT_POLL_MS,
      staleTime: 8_000,
    });

    return {
      error: resolveMobileDuelErrorMessage({
        error: chatQuery.error,
        copy,
        fallback: {
          de: 'Der Lobby-Chat konnte nicht geladen werden.',
          en: 'Could not load the lobby chat.',
          pl: 'Nie udało się pobrać czatu lobby.',
        },
        unauthorized: {
          de: 'Melde dich an, um den Lobby-Chat zu nutzen.',
          en: 'Sign in to use the lobby chat.',
          pl: 'Zaloguj się, aby korzystać z czatu lobby.',
        },
        unauthorizedStatuses: [401, 403],
      }),
      isAuthenticated,
      isLoading: isRestoringAuth || chatQuery.isLoading,
      isRestoringAuth,
      isSending,
      maxMessageLength: KANGUR_DUELS_LOBBY_CHAT_MAX_MESSAGE_LENGTH,
      messages: chatQuery.data?.messages ?? [],
      refresh: async () => {
        await chatQuery.refetch();
      },
      sendMessage: async (message) => {
        const trimmed = message.trim();
        if (!trimmed) {
          return false;
        }

        setIsSending(true);

        try {
          const response = await apiClient.sendDuelLobbyChatMessage(
            {
              message: trimmed,
            },
            { cache: 'no-store' },
          );

          queryClient.setQueryData<KangurDuelLobbyChatListResponse>(queryKey, (current) =>
            appendMessage(current, response.message),
          );

          return true;
        } catch {
          await chatQuery.refetch();
          return false;
        } finally {
          setIsSending(false);
        }
      },
    };
  };

import {
  type KangurMobileLocalizedValue,
} from '../i18n/kangurMobileI18n';

export const readSessionErrorStatus = (error: unknown): number | null => {
  if (typeof error !== 'object' || !error || !('status' in error)) {
    return null;
  }

  return typeof (error as { status?: unknown }).status === 'number'
    ? ((error as { status: number }).status)
    : null;
};

export const readSessionErrorMessage = (error: unknown): string | null => {
  if (!(error instanceof Error)) {
    return null;
  }

  const message = error.message.trim();
  return message.length > 0 ? message : null;
};

export const isFallbackSessionErrorMessage = (message: string): boolean => {
  const normalized = message.toLowerCase();
  return normalized === 'failed to fetch' || normalized.includes('networkerror');
};

export const getUnauthorizedSessionErrorMessage = (
  copy: (value: KangurMobileLocalizedValue<string>) => string,
): string =>
  copy({
    de: 'Melde dich an, um dieses Duell zu öffnen.',
    en: 'Sign in to open this duel.',
    pl: 'Zaloguj się, aby otworzyć ten pojedynek.',
  });

export const resolveSessionMessageWithFallback = (
  message: string | null,
  fallback: string,
): string => {
  if (!message || isFallbackSessionErrorMessage(message)) {
    return fallback;
  }

  return message;
};

export const toSessionErrorMessage = (
  error: unknown,
  fallback: string,
  copy: (value: KangurMobileLocalizedValue<string>) => string,
): string | null => {
  if (!error) {
    return null;
  }

  if (readSessionErrorStatus(error) === 401) {
    return getUnauthorizedSessionErrorMessage(copy);
  }

  return resolveSessionMessageWithFallback(readSessionErrorMessage(error), fallback);
};

import type {
  KangurDuelChoice,
  KangurDuelPlayer,
  KangurDuelQuestion,
  KangurDuelSession,
} from '@kangur/contracts/kangur-duels';

export const resolveCurrentQuestionIndex = (
  duelSession: KangurDuelSession | null,
  isSpectating: boolean,
  player: KangurDuelPlayer | null,
): number | null => {
  if (!duelSession) {
    return null;
  }

  const currentQuestionIndex = isSpectating
    ? duelSession.currentQuestionIndex ?? 0
    : player?.currentQuestionIndex ?? 0;

  return currentQuestionIndex >= duelSession.questionCount
    ? null
    : currentQuestionIndex;
};

export const resolveCurrentQuestion = (
  duelSession: KangurDuelSession | null,
  isSpectating: boolean,
  player: KangurDuelPlayer | null,
): KangurDuelQuestion | null => {
  const currentQuestionIndex = resolveCurrentQuestionIndex(
    duelSession,
    isSpectating,
    player,
  );

  if (!duelSession || currentQuestionIndex === null) {
    return null;
  }

  return duelSession.questions[currentQuestionIndex] ?? null;
};

export const createMobileDuelSpectatorId = (): string =>
  `mobile_spectator_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 10)}`;

import type {
  KangurDuelChoice,
  KangurDuelPlayer,
  KangurDuelQuestion,
  KangurDuelReactionType,
  KangurDuelSpectatorStateResponse,
  KangurDuelSession,
  KangurDuelStateResponse,
} from '@kangur/contracts/kangur-duels';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { useEffect, useState } from 'react';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import {
  useKangurMobileI18n,
} from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import {
  createMobileDuelSpectatorId,
  resolveCurrentQuestion,
} from './useKangurMobileDuelSession.helpers';
import { toSessionErrorMessage } from './useKangurMobileDuelSession.errors';

const MOBILE_DUEL_SESSION_POLL_MS = 4_000;
const MOBILE_DUEL_HEARTBEAT_MS = 15_000;

type UseKangurMobileDuelSessionOptions = {
  spectate?: boolean;
};

export type UseKangurMobileDuelSessionResult = {
  actionError: string | null;
  currentQuestion: KangurDuelQuestion | null;
  error: string | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  isMutating: boolean;
  isRestoringAuth: boolean;
  isSpectating: boolean;
  leaveSession: () => Promise<boolean>;
  player: KangurDuelPlayer | null;
  refresh: () => Promise<void>;
  sendReaction: (type: KangurDuelReactionType) => Promise<void>;
  session: KangurDuelSession | null;
  spectatorCount: number;
  submitAnswer: (choice: KangurDuelChoice) => Promise<void>;
};

export const useKangurMobileDuelSession = (
  sessionId: string | null,
  options: UseKangurMobileDuelSessionOptions = {},
): UseKangurMobileDuelSessionResult => {
  const { copy } = useKangurMobileI18n();
  const queryClient = useQueryClient();
  const { apiBaseUrl, apiClient } = useKangurMobileRuntime();
  const { isLoadingAuth, session } = useKangurMobileAuth();
  const [actionError, setActionError] = useState<string | null>(null);
  const [isMutating, setIsMutating] = useState(false);
  const [spectatorId] = useState(createMobileDuelSpectatorId);
  const learnerIdentity =
    session.user?.activeLearner?.id ??
    session.user?.email ??
    session.user?.id ??
    'guest';
  const isAuthenticated = session.status === 'authenticated';
  const isRestoringAuth = isLoadingAuth && !isAuthenticated;
  const isSpectating = options.spectate === true;
  const normalizedSessionId = sessionId?.trim() ?? '';
  const hasSessionId = normalizedSessionId.length > 0;
  const playerQueryKey = [
    'kangur-mobile',
    'duels',
    'session',
    apiBaseUrl,
    learnerIdentity,
    normalizedSessionId,
  ] as const;
  const spectatorQueryKey = [
    'kangur-mobile',
    'duels',
    'spectator-session',
    apiBaseUrl,
    normalizedSessionId,
    spectatorId,
  ] as const;

  const playerQuery = useQuery({
    enabled: hasSessionId && isAuthenticated && !isSpectating,
    queryKey: playerQueryKey,
    queryFn: async () =>
      apiClient.getDuelState(normalizedSessionId, { cache: 'no-store' }),
    refetchInterval: MOBILE_DUEL_SESSION_POLL_MS,
    staleTime: 2_000,
  });

  const spectatorQuery = useQuery({
    enabled: hasSessionId && isSpectating,
    queryKey: spectatorQueryKey,
    queryFn: async () =>
      apiClient.getDuelSpectatorState(
        normalizedSessionId,
        { spectatorId },
        { cache: 'no-store' },
      ),
    refetchInterval: MOBILE_DUEL_SESSION_POLL_MS,
    staleTime: 2_000,
  });

  const sessionState = playerQuery.data ?? null;
  const spectatorState = spectatorQuery.data ?? null;
  const duelSession = isSpectating
    ? spectatorState?.session ?? null
    : sessionState?.session ?? null;
  const player = isSpectating ? null : sessionState?.player ?? null;
  const currentQuestion = resolveCurrentQuestion(duelSession, isSpectating, player);

  useEffect(() => {
    if (isSpectating || !hasSessionId || !isAuthenticated || !duelSession) {
      return;
    }

    if (
      duelSession.status === 'completed' ||
      duelSession.status === 'aborted'
    ) {
      return;
    }

    const intervalId = setInterval(() => {
      void apiClient
        .heartbeatDuel(
          {
            clientTimestamp: new Date().toISOString(),
            sessionId: normalizedSessionId,
          },
          { cache: 'no-store' },
        )
        .then((response) => {
          queryClient.setQueryData(playerQueryKey, response);
        })
        .catch(() => {
          // The polling query already surfaces fetch failures.
        });
    }, MOBILE_DUEL_HEARTBEAT_MS);

    return () => {
      clearInterval(intervalId);
    };
  }, [
    apiClient,
    duelSession,
    hasSessionId,
    isAuthenticated,
    isSpectating,
    normalizedSessionId,
    playerQueryKey,
    queryClient,
  ]);

  const runMutation = async <TResult>(
    action: () => Promise<TResult>,
    fallbackMessage: string,
  ): Promise<TResult | null> => {
    setIsMutating(true);
    setActionError(null);

    try {
      return await action();
    } catch (error) {
      setActionError(toSessionErrorMessage(error, fallbackMessage, copy));
      return null;
    } finally {
      setIsMutating(false);
    }
  };

  return {
    actionError,
    currentQuestion,
    error: toSessionErrorMessage(
      isSpectating ? spectatorQuery.error : playerQuery.error,
      isSpectating
        ? copy({
            de: 'Das öffentliche Duell konnte nicht geladen werden.',
            en: 'Could not load the public duel.',
            pl: 'Nie udało się pobrać publicznego pojedynku.',
          })
        : copy({
            de: 'Der Duellstatus konnte nicht geladen werden.',
            en: 'Could not load the duel state.',
            pl: 'Nie udało się pobrać stanu pojedynku.',
          }),
      copy,
    ),
    isAuthenticated,
    isLoading: isSpectating ? spectatorQuery.isLoading : isRestoringAuth || playerQuery.isLoading,
    isMutating,
    isRestoringAuth,
    isSpectating,
    leaveSession: async () => {
      if (isSpectating) {
        return false;
      }

      const response = await runMutation(
        async () =>
          apiClient.leaveDuel(
            {
              reason: 'mobile_exit',
              sessionId: normalizedSessionId,
            },
            { cache: 'no-store' },
          ),
        copy({
          de: 'Das Duell konnte nicht verlassen werden.',
          en: 'Could not leave the duel.',
          pl: 'Nie udało się opuścić pojedynku.',
        }),
      );

      if (!response) {
        return false;
      }

      queryClient.setQueryData(playerQueryKey, response);
      return true;
    },
    player,
    refresh: async () => {
      if (isSpectating) {
        await spectatorQuery.refetch();
        return;
      }

      await playerQuery.refetch();
    },
    sendReaction: async (type) => {
      const response = await runMutation(
        async () =>
          apiClient.reactToDuel(
            {
              sessionId: normalizedSessionId,
              type,
            },
            { cache: 'no-store' },
          ),
        copy({
          de: 'Die Reaktion konnte nicht gesendet werden.',
          en: 'Could not send the reaction.',
          pl: 'Nie udało się wysłać reakcji.',
        }),
      );

      if (!response) {
        return;
      }

      const activeQueryKey = isSpectating ? spectatorQueryKey : playerQueryKey;
      queryClient.setQueryData<KangurDuelStateResponse | KangurDuelSpectatorStateResponse>(
        activeQueryKey,
        (current) => {
        if (!current || typeof current !== 'object' || !('session' in current)) {
          return current;
        }

        const currentState = current as {
          player?: KangurDuelPlayer;
          serverTime: string;
          session: KangurDuelSession;
        };
        const existingReactions = currentState.session.recentReactions ?? [];

        return {
          ...currentState,
          session: {
            ...currentState.session,
            recentReactions: [...existingReactions, response.reaction].slice(-8),
          },
        };
        },
      );
    },
    session: duelSession,
    spectatorCount: duelSession?.spectatorCount ?? 0,
    submitAnswer: async (choice) => {
      if (isSpectating || !currentQuestion) {
        return;
      }

      const response = await runMutation(
        async () =>
          apiClient.answerDuel(
            {
              choice,
              clientTimestamp: new Date().toISOString(),
              questionId: currentQuestion.id,
              sessionId: normalizedSessionId,
            },
            { cache: 'no-store' },
          ),
        copy({
          de: 'Die Antwort konnte nicht gesendet werden.',
          en: 'Could not send the answer.',
          pl: 'Nie udało się wysłać odpowiedzi.',
        }),
      );

      if (!response) {
        return;
      }

      queryClient.setQueryData(playerQueryKey, response);
    },
  };
};

import { type useKangurMobileI18n } from '../i18n/kangurMobileI18n';

type DuelCopy = ReturnType<typeof useKangurMobileI18n>['copy'];

export const toDuelsSummaryErrorMessage = (
  error: unknown,
  copy: DuelCopy,
): string | null => {
  if (!error) {
    return null;
  }

  if (typeof error === 'object' && error && 'status' in error) {
    const status = (error as { status?: number }).status;

    if (status === 401) {
      return copy({
        de: 'Melde dich an, um Duellstatistiken zu laden.',
        en: 'Sign in to load duel stats.',
        pl: 'Zaloguj się, aby pobrać statystyki pojedynków.',
      });
    }
  }

  if (!(error instanceof Error)) {
    return copy({
      de: 'Die Duellstatistiken konnten nicht geladen werden.',
      en: 'Could not load duel stats.',
      pl: 'Nie udało się pobrać statystyk pojedynków.',
    });
  }

  const message = error.message.trim();
  if (!message) {
    return copy({
      de: 'Die Duellstatistiken konnten nicht geladen werden.',
      en: 'Could not load duel stats.',
      pl: 'Nie udało się pobrać statystyk pojedynków.',
    });
  }

  const normalized = message.toLowerCase();
  if (normalized === 'failed to fetch' || normalized.includes('networkerror')) {
    return copy({
      de: 'Die Duellstatistiken konnten nicht geladen werden.',
      en: 'Could not load duel stats.',
      pl: 'Nie udało się pobrać statystyk pojedynków.',
    });
  }

  return message;
};

