import { type Href, useLocalSearchParams } from 'expo-router';

import type { KangurScore } from '@kangur/contracts/kangur';
import {
  buildKangurHomeDebugProofViewModel,
  resolveKangurHomeDebugProofOperation,
} from './homeDebugProof';
import {
  type KangurMobileHomeLessonCheckpointItem,
  useKangurMobileHomeLessonCheckpoints,
} from './useKangurMobileHomeLessonCheckpoints';
import { useKangurMobileRecentResults } from './useKangurMobileRecentResults';
import { useKangurMobileTrainingFocus } from './useKangurMobileTrainingFocus';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { createKangurPracticeHref } from '../practice/practiceHref';
import {
  formatKangurMobileScoreOperation,
  type KangurMobileOperationPerformance,
} from '../scores/mobileScoreSummary';
import { PRACTICE_ROUTE } from './home-screen-constants';

export type HomeRecentResultsViewModel = {
  error: string | null;
  isEnabled: boolean;
  isLoading: boolean;
  isRestoringAuth: boolean;
  refresh: () => Promise<void>;
  results: KangurScore[];
};

export type HomeTrainingFocusViewModel = {
  error: string | null;
  isEnabled: boolean;
  isLoading: boolean;
  isRestoringAuth: boolean;
  recentResults: KangurScore[];
  refresh: () => Promise<void>;
  strongestLessonFocus: string | null;
  strongestOperation: KangurMobileOperationPerformance | null;
  weakestLessonFocus: string | null;
  weakestOperation: KangurMobileOperationPerformance | null;
};

export type HomeScoreViewModel = {
  homeDebugProof: ReturnType<typeof buildKangurHomeDebugProofViewModel>;
  homeHeroFocusHref: Href;
  homeHeroFocusLabel: string;
  homeHeroRecentResult: KangurScore | null;
  recentResults: HomeRecentResultsViewModel;
  trainingFocus: HomeTrainingFocusViewModel;
};

type HomeScoreStateProps = {
  areDeferredHomePanelsReady: boolean;
  children: (viewModel: HomeScoreViewModel) => React.ReactNode;
  debugProofOperation: string | null;
};

type HomeHeroLatestLessonCheckpointViewModel = {
  homeHeroRecentCheckpoint: KangurMobileHomeLessonCheckpointItem | null;
  homeHeroRecentCheckpointCount: number;
};

type HomeHeroLatestLessonCheckpointStateProps = {
  children: (viewModel: HomeHeroLatestLessonCheckpointViewModel) => React.ReactNode;
  isEnabled: boolean;
  initialLatestLessonCheckpoint: KangurMobileHomeLessonCheckpointItem | null;
  isLiveProgressReady: boolean;
};

const noopRefreshHomeScoreViewModel = async (): Promise<void> => {};

function LiveHomeHeroLatestLessonCheckpointState({
  children,
}: Pick<HomeHeroLatestLessonCheckpointStateProps, 'children'>): React.JSX.Element {
  const latestLessonCheckpoint = useKangurMobileHomeLessonCheckpoints({
    limit: 1,
  });

  return (
    <>
      {children({
        homeHeroRecentCheckpoint: latestLessonCheckpoint.recentCheckpoints[0] ?? null,
        homeHeroRecentCheckpointCount: latestLessonCheckpoint.recentCheckpoints.length,
      })}
    </>
  );
}

export function HomeHeroLatestLessonCheckpointState({
  children,
  isEnabled,
  initialLatestLessonCheckpoint,
  isLiveProgressReady,
}: HomeHeroLatestLessonCheckpointStateProps): React.JSX.Element {
  if (!isEnabled) {
    return (
      <>
        {children({
          homeHeroRecentCheckpoint: null,
          homeHeroRecentCheckpointCount: 0,
        })}
      </>
    );
  }

  if (!isLiveProgressReady) {
    return (
      <>
        {children({
          homeHeroRecentCheckpoint: initialLatestLessonCheckpoint,
          homeHeroRecentCheckpointCount: initialLatestLessonCheckpoint ? 1 : 0,
        })}
      </>
    );
  }

  return <LiveHomeHeroLatestLessonCheckpointState>{children}</LiveHomeHeroLatestLessonCheckpointState>;
}

function LiveHomeDebugProofOperationState({
  children,
}: {
  children: (debugProofOperation: string | null) => React.ReactNode;
}): React.JSX.Element {
  const params = useLocalSearchParams<{
    debugProofOperation?: string | string[];
  }>();

  return <>{children(resolveKangurHomeDebugProofOperation(params.debugProofOperation))}</>;
}

export function HomeDebugProofOperationState({
  children,
}: {
  children: (debugProofOperation: string | null) => React.ReactNode;
}): React.JSX.Element {
  if (!__DEV__) {
    return <>{children(null)}</>;
  }

  return <LiveHomeDebugProofOperationState>{children}</LiveHomeDebugProofOperationState>;
}

const createHomeDebugProofViewModel = (input: {
  isEnabled: boolean;
  isLoading: boolean;
  locale: 'pl' | 'en' | 'de';
  operation: string | null;
  recentResults: KangurScore[];
  strongestOperation: KangurMobileOperationPerformance | null;
  weakestOperation: KangurMobileOperationPerformance | null;
}) =>
  input.operation
    ? buildKangurHomeDebugProofViewModel(input)
    : null;

export function DeferredAuthenticatedHomeScoreState({
  areDeferredHomePanelsReady,
  children,
  debugProofOperation,
}: HomeScoreStateProps): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const recentResults = {
    error: null,
    isEnabled: false,
    isLoading: false,
    isRestoringAuth: false,
    refresh: noopRefreshHomeScoreViewModel,
    results: [],
  } satisfies HomeRecentResultsViewModel;
  const trainingFocus = {
    error: null,
    isEnabled: false,
    isLoading: false,
    isRestoringAuth: false,
    recentResults: [],
    refresh: noopRefreshHomeScoreViewModel,
    strongestLessonFocus: null,
    strongestOperation: null,
    weakestLessonFocus: null,
    weakestOperation: null,
  } satisfies HomeTrainingFocusViewModel;
  const homeDebugProof = createHomeDebugProofViewModel({
    isEnabled: false,
    isLoading: !areDeferredHomePanelsReady,
    locale,
    operation: debugProofOperation,
    recentResults: recentResults.results,
    strongestOperation: null,
    weakestOperation: null,
  });

  return (
    <>
      {children({
        homeDebugProof,
        homeHeroFocusHref: PRACTICE_ROUTE,
        homeHeroFocusLabel: copy({
          de: 'Gemischtes Training',
          en: 'Mixed practice',
          pl: 'Trening mieszany',
        }),
        homeHeroRecentResult: null,
        recentResults,
        trainingFocus,
      })}
    </>
  );
}

export function LiveAuthenticatedHomeScoreState({
  areDeferredHomePanelsReady,
  areDeferredHomeScoreRefreshReady,
  children,
  debugProofOperation,
}: HomeScoreStateProps & {
  areDeferredHomeScoreRefreshReady: boolean;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const cachedRecentResults = useKangurMobileRecentResults({
    enabled: false,
  });
  const trainingFocus = useKangurMobileTrainingFocus({
    enabled: areDeferredHomeScoreRefreshReady,
    recentResultsLimit: 3,
  });
  const hasResolvedHomeScoreInsights =
    trainingFocus.isEnabled &&
    !trainingFocus.isLoading &&
    !trainingFocus.isRestoringAuth &&
    !trainingFocus.error;
  const recentResults = {
    error: trainingFocus.isEnabled ? trainingFocus.error : cachedRecentResults.error,
    isEnabled: trainingFocus.isEnabled,
    isLoading: trainingFocus.isEnabled
      ? trainingFocus.isLoading
      : cachedRecentResults.isLoading,
    isRestoringAuth: trainingFocus.isEnabled
      ? trainingFocus.isRestoringAuth
      : cachedRecentResults.isRestoringAuth,
    refresh: trainingFocus.isEnabled ? trainingFocus.refresh : cachedRecentResults.refresh,
    results: hasResolvedHomeScoreInsights
      ? trainingFocus.recentResults
      : cachedRecentResults.results,
  };
  const homeDebugProof = createHomeDebugProofViewModel({
    isEnabled:
      recentResults.isEnabled &&
      (!areDeferredHomePanelsReady || trainingFocus.isEnabled),
    isLoading:
      recentResults.isLoading ||
      !areDeferredHomePanelsReady ||
      trainingFocus.isLoading,
    locale,
    operation: debugProofOperation,
    recentResults: recentResults.results,
    strongestOperation: trainingFocus.strongestOperation,
    weakestOperation: trainingFocus.weakestOperation,
  });

  return (
    <>
      {children({
        homeDebugProof,
        homeHeroFocusHref: trainingFocus.weakestOperation
          ? createKangurPracticeHref(trainingFocus.weakestOperation.operation)
          : PRACTICE_ROUTE,
        homeHeroFocusLabel: trainingFocus.weakestOperation
          ? formatKangurMobileScoreOperation(
              trainingFocus.weakestOperation.operation,
              locale,
            )
          : copy({
              de: 'Gemischtes Training',
              en: 'Mixed practice',
              pl: 'Trening mieszany',
            }),
        homeHeroRecentResult: recentResults.results[0] ?? null,
        recentResults,
        trainingFocus,
      })}
    </>
  );
}

export function AnonymousHomeScoreState({
  areDeferredHomePanelsReady,
  children,
  debugProofOperation,
  isRestoringAuth,
}: HomeScoreStateProps & {
  isRestoringAuth: boolean;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const recentResults = {
    error: null,
    isEnabled: false,
    isLoading: isRestoringAuth,
    isRestoringAuth,
    refresh: noopRefreshHomeScoreViewModel,
    results: [],
  } satisfies HomeRecentResultsViewModel;
  const trainingFocus = {
    error: null,
    isEnabled: false,
    isLoading: isRestoringAuth,
    isRestoringAuth,
    recentResults: [],
    refresh: noopRefreshHomeScoreViewModel,
    strongestLessonFocus: null,
    strongestOperation: null,
    weakestLessonFocus: null,
    weakestOperation: null,
  } satisfies HomeTrainingFocusViewModel;
  const homeDebugProof = createHomeDebugProofViewModel({
    isEnabled: false,
    isLoading:
      recentResults.isLoading ||
      !areDeferredHomePanelsReady ||
      trainingFocus.isLoading,
    locale,
    operation: debugProofOperation,
    recentResults: recentResults.results,
    strongestOperation: null,
    weakestOperation: null,
  });

  return (
    <>
      {children({
        homeDebugProof,
        homeHeroFocusHref: PRACTICE_ROUTE,
        homeHeroFocusLabel: copy({
          de: 'Gemischtes Training',
          en: 'Mixed practice',
          pl: 'Trening mieszany',
        }),
        homeHeroRecentResult: null,
        recentResults,
        trainingFocus,
      })}
    </>
  );
}

import type { KangurAuthSession } from '@kangur/platform';

import {
  getKangurMobileLocalizedValue,
  type KangurMobileLocale,
} from '../i18n/kangurMobileI18n';

export type KangurHomeAuthBoundaryViewModel = {
  developerAutoSignInLabel: string | null;
  isRestoringLearnerSession: boolean;
  showLearnerCredentialsForm: boolean;
  statusLabel: string;
  userLabel: string;
};

const STATUS_LABELS = {
  anonymous: {
    de: 'anonym',
    en: 'anonymous',
    pl: 'anonimowy',
  },
  authenticated: {
    de: 'angemeldet',
    en: 'signed in',
    pl: 'zalogowany',
  },
  loading: {
    de: 'laden',
    en: 'loading',
    pl: 'ladowanie',
  },
  restoring: {
    de: 'wird wiederhergestellt',
    en: 'restoring',
    pl: 'przywracanie',
  },
} as const;

const ACTOR_TYPE_LABELS = {
  admin: {
    de: 'admin',
    en: 'admin',
    pl: 'admin',
  },
  learner: {
    de: 'schuler',
    en: 'learner',
    pl: 'uczen',
  },
  parent: {
    de: 'elternteil',
    en: 'parent',
    pl: 'rodzic',
  },
} as const;

const RESTORING_SESSION_LABEL = {
  de: 'wiederherstellung der anmeldung',
  en: 'restoring sign-in',
  pl: 'przywracanie logowania',
} as const;

export const getKangurHomeAuthBoundaryViewModel = ({
  authError,
  developerAutoSignInEnabled,
  hasAttemptedDeveloperAutoSignIn,
  isLoadingAuth,
  locale = 'pl',
  session,
  supportsLearnerCredentials,
}: {
  authError: string | null;
  developerAutoSignInEnabled: boolean;
  hasAttemptedDeveloperAutoSignIn: boolean;
  isLoadingAuth: boolean;
  locale?: KangurMobileLocale;
  session: KangurAuthSession;
  supportsLearnerCredentials: boolean;
}): KangurHomeAuthBoundaryViewModel => {
  const isRestoringLearnerSession =
    isLoadingAuth && session.status !== 'authenticated';
  const statusLabel = getKangurMobileLocalizedValue(
    isRestoringLearnerSession
      ? STATUS_LABELS.restoring
      : isLoadingAuth
        ? STATUS_LABELS.loading
        : session.status === 'authenticated'
          ? STATUS_LABELS.authenticated
          : STATUS_LABELS.anonymous,
    locale,
  );
  const actorTypeLabel =
    session.user?.actorType === 'learner'
      ? ACTOR_TYPE_LABELS['learner'][locale]
      : session.user?.actorType === 'parent'
        ? ACTOR_TYPE_LABELS['parent'][locale]
      : session.user?.actorType === 'admin'
          ? ACTOR_TYPE_LABELS['admin'][locale]
          : session.user?.actorType ?? null;

  return {
    developerAutoSignInLabel: !developerAutoSignInEnabled
      ? null
      : session.status === 'authenticated'
        ? 'authenticated'
        : hasAttemptedDeveloperAutoSignIn
          ? isLoadingAuth
            ? 'attempting'
            : authError
              ? 'failed'
              : 'attempted'
          : isLoadingAuth
            ? 'waiting'
            : 'ready',
    isRestoringLearnerSession,
    showLearnerCredentialsForm:
      supportsLearnerCredentials &&
      !isRestoringLearnerSession &&
      session.status !== 'authenticated',
    statusLabel,
    userLabel: isRestoringLearnerSession
      ? getKangurMobileLocalizedValue(RESTORING_SESSION_LABEL, locale)
      : session.user
        ? `${session.user.full_name} (${actorTypeLabel})`
        : getKangurMobileLocalizedValue(STATUS_LABELS.anonymous, locale),
  };
};

import type { KangurScore } from '@kangur/contracts/kangur';

import {
  getKangurMobileLocalizedValue,
  type KangurMobileLocale,
} from '../i18n/kangurMobileI18n';
import { formatKangurMobileScoreOperation } from '../scores/mobileScoreSummary';

type KangurHomeDebugProofOperationPerformance = {
  averageAccuracyPercent: number;
  operation: string;
  sessions: number;
};

export type KangurHomeDebugProofCheckStatus = 'info' | 'missing' | 'ready';

export type KangurHomeDebugProofCheck = {
  detail: string;
  label: string;
  status: KangurHomeDebugProofCheckStatus;
};

export type KangurHomeDebugProofViewModel = {
  checks: KangurHomeDebugProofCheck[];
  operation: string;
  operationLabel: string;
};

export const resolveKangurHomeDebugProofOperation = (
  value: string | string[] | null | undefined,
): string | null => {
  const rawValue = Array.isArray(value) ? value[0] : value;
  const normalizedValue = rawValue?.trim();
  return normalizedValue ? normalizedValue : null;
};

export const buildKangurHomeDebugProofViewModel = (input: {
  isEnabled: boolean;
  isLoading: boolean;
  locale?: KangurMobileLocale;
  operation: string | null;
  recentResults: KangurScore[];
  strongestOperation: KangurHomeDebugProofOperationPerformance | null;
  weakestOperation: KangurHomeDebugProofOperationPerformance | null;
}): KangurHomeDebugProofViewModel | null => {
  if (!input.operation) {
    return null;
  }

  const locale = input.locale ?? 'pl';

  if (input.isLoading) {
    return {
      checks: [
        {
          detail: getKangurMobileLocalizedValue(
            {
              de: 'Die Anmeldung und die Ergebnisdaten für den Start werden wiederhergestellt.',
              en: 'We are restoring sign-in and results data for home.',
              pl: 'Przywracamy logowanie i dane wyników dla startu.',
            },
            locale,
          ),
          label: getKangurMobileLocalizedValue(
            {
              de: 'Ergebnisse zum Start',
              en: 'Home results',
              pl: 'Wyniki na starcie',
            },
            locale,
          ),
          status: 'info',
        },
      ],
      operation: input.operation,
      operationLabel: formatKangurMobileScoreOperation(input.operation, locale),
    };
  }

  if (!input.isEnabled) {
    return {
      checks: [
        {
          detail: getKangurMobileLocalizedValue(
            {
              de: 'Die Ergebnisse zum Start sind für dieses Konto noch nicht aktiviert.',
              en: 'Home results are not enabled yet for this account.',
              pl: 'Wyniki na starcie nie są jeszcze włączone dla tego konta.',
            },
            locale,
          ),
          label: getKangurMobileLocalizedValue(
            {
              de: 'Ergebnisse zum Start',
              en: 'Home results',
              pl: 'Wyniki na starcie',
            },
            locale,
          ),
          status: 'missing',
        },
      ],
      operation: input.operation,
      operationLabel: formatKangurMobileScoreOperation(input.operation, locale),
    };
  }

  const recentResult = input.recentResults.find(
    (result) => result.operation === input.operation,
  );
  const strongestOperation = input.strongestOperation;
  const weakestOperation = input.weakestOperation;

  return {
    checks: [
      recentResult
        ? {
            detail: getKangurMobileLocalizedValue(
              {
                de: `${recentResult.correct_answers}/${recentResult.total_questions} in den letzten Ergebnissen.`,
                en: `${recentResult.correct_answers}/${recentResult.total_questions} in the latest results.`,
                pl: `${recentResult.correct_answers}/${recentResult.total_questions} w ostatnich wynikach.`,
              },
              locale,
            ),
            label: getKangurMobileLocalizedValue(
              {
                de: 'Ergebniszentrale',
                en: 'Results hub',
                pl: 'Centrum wyników',
              },
              locale,
            ),
            status: 'ready',
          }
        : {
            detail: getKangurMobileLocalizedValue(
              {
                de: 'Dieser Modus ist in der Ergebniszentrale noch nicht sichtbar.',
                en: 'This mode is not visible in the results hub yet.',
                pl: 'Ten tryb nie jest jeszcze widoczny w centrum wyników.',
              },
              locale,
            ),
            label: getKangurMobileLocalizedValue(
              {
                de: 'Ergebniszentrale',
                en: 'Results hub',
                pl: 'Centrum wyników',
              },
              locale,
            ),
            status: 'missing',
          },
      strongestOperation?.operation === input.operation
        ? {
            detail: getKangurMobileLocalizedValue(
              {
                de: `Stärkster Modus hier: ${strongestOperation.averageAccuracyPercent}% in ${strongestOperation.sessions} Versuchen.`,
                en: `Strongest mode here: ${strongestOperation.averageAccuracyPercent}% across ${strongestOperation.sessions} attempts.`,
                pl: `Najmocniejszy tryb tutaj: ${strongestOperation.averageAccuracyPercent}% w ${strongestOperation.sessions} podejściach.`,
              },
              locale,
            ),
            label: getKangurMobileLocalizedValue(
              {
                de: 'Trainingsfokus',
                en: 'Training focus',
                pl: 'Fokus treningowy',
              },
              locale,
            ),
            status: 'ready',
          }
        : weakestOperation?.operation === input.operation
          ? {
              detail: getKangurMobileLocalizedValue(
                {
                  de: `Wiederholungsmodus hier: ${weakestOperation.averageAccuracyPercent}% in ${weakestOperation.sessions} Versuchen.`,
                  en: `Review mode here: ${weakestOperation.averageAccuracyPercent}% across ${weakestOperation.sessions} attempts.`,
                  pl: `Tryb do powtórki tutaj: ${weakestOperation.averageAccuracyPercent}% w ${weakestOperation.sessions} podejściach.`,
                },
                locale,
              ),
              label: getKangurMobileLocalizedValue(
                {
                  de: 'Trainingsfokus',
                  en: 'Training focus',
                  pl: 'Fokus treningowy',
                },
                locale,
              ),
              status: 'ready',
            }
          : {
              detail: getKangurMobileLocalizedValue(
                {
                  de: 'Der Trainingsfokus ist schon bereit, aber dieser Modus ist gerade weder die stärkste noch die schwächste Karte.',
                  en: 'The training focus is ready, but this mode is neither the strongest nor the weakest card right now.',
                  pl: 'Fokus treningowy jest już gotowy, ale ten tryb nie jest teraz najmocniejszą ani najsłabszą kartą.',
                },
                locale,
              ),
              label: getKangurMobileLocalizedValue(
                {
                  de: 'Trainingsfokus',
                  en: 'Training focus',
                  pl: 'Fokus treningowy',
                },
                locale,
              ),
              status: 'missing',
            },
    ],
    operation: input.operation,
    operationLabel: formatKangurMobileScoreOperation(input.operation, locale),
  };
};

import { kangurDuelLobbyEntrySchema, type KangurDuelLobbyEntry } from '@kangur/contracts/kangur-duels';
import type { KangurClientStorageAdapter } from '@kangur/platform';

import { MOBILE_HOME_DUEL_LOBBY_QUERY_LIMIT } from './homeDuelLobbyQuery';

const KANGUR_MOBILE_HOME_DUEL_INVITES_STORAGE_KEY =
  'kangur.mobile.home.duels.privateLobby';

const parsePersistedHomeDuelInvitesStore = (
  rawSnapshot: string | null,
): Record<string, KangurDuelLobbyEntry[]> => {
  const normalizedRawSnapshot = rawSnapshot?.trim() ?? '';
  if (!normalizedRawSnapshot) {
    return {};
  }

  try {
    const parsedSnapshot = JSON.parse(normalizedRawSnapshot) as unknown;
    if (
      !parsedSnapshot ||
      typeof parsedSnapshot !== 'object' ||
      Array.isArray(parsedSnapshot)
    ) {
      return {};
    }

    return Object.entries(parsedSnapshot).reduce<Record<string, KangurDuelLobbyEntry[]>>(
      (snapshot, [identityKey, value]) => {
        const parsedEntries = kangurDuelLobbyEntrySchema
          .array()
          .max(MOBILE_HOME_DUEL_LOBBY_QUERY_LIMIT)
          .safeParse(value);
        if (parsedEntries.success) {
          snapshot[identityKey] = parsedEntries.data;
        }
        return snapshot;
      },
      {},
    );
  } catch {
    return {};
  }
};

export const resolvePersistedKangurMobileHomeDuelInvites = ({
  learnerIdentity,
  storage,
}: {
  learnerIdentity: string;
  storage: KangurClientStorageAdapter;
}): KangurDuelLobbyEntry[] | null => {
  const store = parsePersistedHomeDuelInvitesStore(
    storage.getItem(KANGUR_MOBILE_HOME_DUEL_INVITES_STORAGE_KEY),
  );
  return store[learnerIdentity] ?? null;
};

export const persistKangurMobileHomeDuelInvites = ({
  entries,
  learnerIdentity,
  storage,
}: {
  entries: KangurDuelLobbyEntry[];
  learnerIdentity: string;
  storage: KangurClientStorageAdapter;
}): void => {
  const store = parsePersistedHomeDuelInvitesStore(
    storage.getItem(KANGUR_MOBILE_HOME_DUEL_INVITES_STORAGE_KEY),
  );
  store[learnerIdentity] = entries.slice(0, MOBILE_HOME_DUEL_LOBBY_QUERY_LIMIT);
  storage.setItem(
    KANGUR_MOBILE_HOME_DUEL_INVITES_STORAGE_KEY,
    JSON.stringify(store),
  );
};

import {
  KANGUR_LESSON_CATALOG,
  getKangurPracticeOperationForLessonComponent,
  getLocalizedKangurCoreLessonTitle,
} from '@kangur/core';
import {
  createDefaultKangurProgressState,
  kangurLessonMasteryEntrySchema,
  type KangurLessonMastery,
  type KangurLessonMasteryEntry,
  type KangurProgressState,
} from '@kangur/contracts/kangur';
import type { Href } from 'expo-router';
import type { KangurClientStorageAdapter } from '@kangur/platform';

import { KANGUR_MOBILE_ACTIVE_LEARNER_STORAGE_KEY } from '../auth/mobileAuthStorageKeys';
import { createKangurLessonHref } from '../lessons/lessonHref';
import { createKangurPracticeHref } from '../practice/practiceHref';

const KANGUR_MOBILE_HOME_LESSON_CHECKPOINTS_STORAGE_KEY =
  'kangur.mobile.home.lessonCheckpoints';
const MOBILE_HOME_LESSON_CHECKPOINTS_SNAPSHOT_LIMIT = 2;

export type KangurMobileHomeLessonCheckpointItem = {
  attempts: number;
  bestScorePercent: number;
  componentId: string;
  emoji: string;
  lastCompletedAt: string;
  lastScorePercent: number;
  lessonHref: Href;
  masteryPercent: number;
  practiceHref: Href | null;
  title: string;
};

type PersistedHomeLessonCheckpointsStore = Record<string, KangurLessonMastery>;

const resolveTimestamp = (value: string | null): number => {
  if (!value) {
    return Number.NEGATIVE_INFINITY;
  }

  const parsed = Date.parse(value);
  return Number.isFinite(parsed) ? parsed : Number.NEGATIVE_INFINITY;
};

const compareLessonCheckpointEntries = (
  [leftComponentId, leftMastery]: [string, KangurLessonMasteryEntry],
  [rightComponentId, rightMastery]: [string, KangurLessonMasteryEntry],
): number => {
  const timestampDelta =
    resolveTimestamp(rightMastery.lastCompletedAt) - resolveTimestamp(leftMastery.lastCompletedAt);
  if (timestampDelta !== 0) {
    return timestampDelta;
  }

  if (rightMastery.lastScorePercent !== leftMastery.lastScorePercent) {
    return rightMastery.lastScorePercent - leftMastery.lastScorePercent;
  }

  return leftComponentId.localeCompare(rightComponentId);
};

const selectRecentCheckpointEntries = (
  lessonMastery: KangurProgressState['lessonMastery'],
  limit: number,
): Array<[string, KangurLessonMasteryEntry]> => {
  const recentEntries: Array<[string, KangurLessonMasteryEntry]> = [];

  for (const [componentId, mastery] of Object.entries(lessonMastery)) {
    if (typeof mastery.lastCompletedAt !== 'string') {
      continue;
    }

    const candidateEntry: [string, KangurLessonMasteryEntry] = [componentId, mastery];
    const insertIndex = recentEntries.findIndex(
      (entry) => compareLessonCheckpointEntries(candidateEntry, entry) < 0,
    );

    if (insertIndex === -1) {
      recentEntries.push(candidateEntry);
    } else {
      recentEntries.splice(insertIndex, 0, candidateEntry);
    }

    if (recentEntries.length > limit) {
      recentEntries.length = limit;
    }
  }

  return recentEntries;
};

const parsePersistedHomeLessonCheckpointStore = (
  rawSnapshot: string | null,
): PersistedHomeLessonCheckpointsStore => {
  const normalizedRawSnapshot = rawSnapshot?.trim() ?? '';
  if (!normalizedRawSnapshot) {
    return {};
  }

  try {
    const parsedSnapshot = JSON.parse(normalizedRawSnapshot) as unknown;
    if (
      !parsedSnapshot ||
      typeof parsedSnapshot !== 'object' ||
      Array.isArray(parsedSnapshot)
    ) {
      return {};
    }

    return Object.entries(parsedSnapshot).reduce<PersistedHomeLessonCheckpointsStore>(
      (snapshot, [identityKey, value]) => {
        if (!value || typeof value !== 'object' || Array.isArray(value)) {
          return snapshot;
        }

        const normalizedLessonMastery = Object.entries(
          value as Record<string, unknown>,
        ).reduce<KangurLessonMastery>((masterySnapshot, [componentId, masteryValue]) => {
          const parsedEntry = kangurLessonMasteryEntrySchema.safeParse(masteryValue);
          if (parsedEntry.success) {
            masterySnapshot[componentId] = parsedEntry.data;
          }
          return masterySnapshot;
        }, {});

        snapshot[identityKey] = normalizedLessonMastery;
        return snapshot;
      },
      {},
    );
  } catch {
    return {};
  }
};

const normalizeCheckpointLimit = (limit: number): number =>
  Math.min(
    MOBILE_HOME_LESSON_CHECKPOINTS_SNAPSHOT_LIMIT,
    Math.max(1, Math.round(limit)),
  );

const mapLessonCheckpointEntriesToItems = (
  entries: Array<[string, KangurLessonMasteryEntry]>,
  locale: string | null | undefined,
): KangurMobileHomeLessonCheckpointItem[] =>
  entries.map(([componentId, mastery]) => {
    const lessonCatalogEntry = KANGUR_LESSON_CATALOG[componentId];
    const practiceOperation = getKangurPracticeOperationForLessonComponent(
      componentId as Parameters<typeof getKangurPracticeOperationForLessonComponent>[0],
    );

    return {
      attempts: mastery.attempts,
      bestScorePercent: mastery.bestScorePercent,
      componentId,
      emoji: lessonCatalogEntry?.emoji ?? '📘',
      lastCompletedAt: mastery.lastCompletedAt ?? '',
      lastScorePercent: mastery.lastScorePercent,
      lessonHref: createKangurLessonHref(componentId),
      masteryPercent: mastery.masteryPercent,
      practiceHref: practiceOperation ? createKangurPracticeHref(practiceOperation) : null,
      title: getLocalizedKangurCoreLessonTitle(
        componentId,
        locale,
        lessonCatalogEntry?.title,
      ),
    };
  });

export const resolveKangurMobileHomeLessonCheckpointIdentity = (
  storage: KangurClientStorageAdapter,
): string => {
  const learnerIdentity =
    storage.getItem(KANGUR_MOBILE_ACTIVE_LEARNER_STORAGE_KEY)?.trim() ?? '';
  return learnerIdentity || 'guest';
};

export const buildPersistedKangurMobileHomeLessonCheckpointSnapshot = ({
  limit = MOBILE_HOME_LESSON_CHECKPOINTS_SNAPSHOT_LIMIT,
  progress,
}: {
  limit?: number;
  progress: KangurProgressState;
}): KangurLessonMastery =>
  Object.fromEntries(
    selectRecentCheckpointEntries(
      progress.lessonMastery,
      normalizeCheckpointLimit(limit),
    ),
  );

export const persistKangurMobileHomeLessonCheckpoints = ({
  learnerIdentity,
  snapshot,
  storage,
}: {
  learnerIdentity: string;
  snapshot: KangurLessonMastery;
  storage: KangurClientStorageAdapter;
}): void => {
  const store = parsePersistedHomeLessonCheckpointStore(
    storage.getItem(KANGUR_MOBILE_HOME_LESSON_CHECKPOINTS_STORAGE_KEY),
  );
  store[learnerIdentity] = snapshot;
  storage.setItem(
    KANGUR_MOBILE_HOME_LESSON_CHECKPOINTS_STORAGE_KEY,
    JSON.stringify(store),
  );
};

export const resolvePersistedKangurMobileHomeLessonCheckpoints = ({
  learnerIdentity,
  limit = MOBILE_HOME_LESSON_CHECKPOINTS_SNAPSHOT_LIMIT,
  locale,
  storage,
}: {
  learnerIdentity: string;
  limit?: number;
  locale: string | null | undefined;
  storage: KangurClientStorageAdapter;
}): KangurMobileHomeLessonCheckpointItem[] | null => {
  const store = parsePersistedHomeLessonCheckpointStore(
    storage.getItem(KANGUR_MOBILE_HOME_LESSON_CHECKPOINTS_STORAGE_KEY),
  );
  const persistedSnapshot = store[learnerIdentity];
  if (!persistedSnapshot || Object.keys(persistedSnapshot).length === 0) {
    return null;
  }

  const progressSnapshot = createDefaultKangurProgressState();
  progressSnapshot.lessonMastery = persistedSnapshot;

  return mapLessonCheckpointEntriesToItems(
    selectRecentCheckpointEntries(
      progressSnapshot.lessonMastery,
      normalizeCheckpointLimit(limit),
    ),
    locale,
  );
};

import { startTransition, useEffect, useState } from 'react';
import { InteractionManager } from 'react-native';

const HOME_SCREEN_DEFERRED_PANELS_FALLBACK_TIMEOUT_MS = 240;
const deferredHomePanelCallbacks = new Set<() => void>();

let deferredHomePanelsInteractionTask:
  | ReturnType<typeof InteractionManager.runAfterInteractions>
  | null = null;
let deferredHomePanelsFallbackTimeoutId: ReturnType<typeof setTimeout> | null = null;
let cancelDeferredHomePanelsFrame = () => {};
let isDeferredHomePanelsFrameScheduled = false;

const scheduleDeferredHomePanelsFrame = (callback: () => void): (() => void) => {
  if (typeof requestAnimationFrame === 'function') {
    const frameId = requestAnimationFrame(() => {
      callback();
    });

    return () => {
      if (typeof cancelAnimationFrame === 'function') {
        cancelAnimationFrame(frameId);
      }
    };
  }

  const timeoutId = setTimeout(callback, 16);
  return () => {
    clearTimeout(timeoutId);
  };
};

const clearDeferredHomePanelsFallbackTimeout = (): void => {
  if (deferredHomePanelsFallbackTimeoutId === null) {
    return;
  }

  clearTimeout(deferredHomePanelsFallbackTimeoutId);
  deferredHomePanelsFallbackTimeoutId = null;
};

const clearDeferredHomePanelsSchedule = (): void => {
  clearDeferredHomePanelsFallbackTimeout();
  deferredHomePanelsInteractionTask?.cancel?.();
  deferredHomePanelsInteractionTask = null;
  cancelDeferredHomePanelsFrame();
  cancelDeferredHomePanelsFrame = () => {};
  isDeferredHomePanelsFrameScheduled = false;
};

const flushDeferredHomePanelCallbacks = (): void => {
  const callbacks = Array.from(deferredHomePanelCallbacks);
  deferredHomePanelCallbacks.clear();
  clearDeferredHomePanelsSchedule();

  if (callbacks.length === 0) {
    return;
  }

  startTransition(() => {
    for (const callback of callbacks) {
      callback();
    }
  });
};

const scheduleDeferredHomePanelsSettle = (): void => {
  if (isDeferredHomePanelsFrameScheduled) {
    return;
  }

  deferredHomePanelsInteractionTask = null;
  clearDeferredHomePanelsFallbackTimeout();
  isDeferredHomePanelsFrameScheduled = true;
  cancelDeferredHomePanelsFrame = scheduleDeferredHomePanelsFrame(
    flushDeferredHomePanelCallbacks,
  );
};

const ensureDeferredHomePanelsSchedule = (): void => {
  if (
    deferredHomePanelCallbacks.size === 0 ||
    deferredHomePanelsInteractionTask !== null ||
    deferredHomePanelsFallbackTimeoutId !== null ||
    isDeferredHomePanelsFrameScheduled
  ) {
    return;
  }

  deferredHomePanelsInteractionTask = InteractionManager.runAfterInteractions(
    scheduleDeferredHomePanelsSettle,
  );

  deferredHomePanelsFallbackTimeoutId = setTimeout(
    scheduleDeferredHomePanelsSettle,
    HOME_SCREEN_DEFERRED_PANELS_FALLBACK_TIMEOUT_MS,
  );
};

const scheduleDeferredHomePanelsCallback = (callback: () => void): (() => void) => {
  deferredHomePanelCallbacks.add(callback);
  ensureDeferredHomePanelsSchedule();

  return () => {
    deferredHomePanelCallbacks.delete(callback);

    if (deferredHomePanelCallbacks.size === 0) {
      clearDeferredHomePanelsSchedule();
    }
  };
};

export const useHomeScreenDeferredPanelSequence = <const TPanelKeys extends readonly string[]>(
  panelKeys: TPanelKeys,
  isBlocked: boolean,
): { [TIndex in keyof TPanelKeys]: boolean } => {
  const [readyCount, setReadyCount] = useState(0);
  const currentPanelKey = panelKeys[readyCount] ?? null;

  useEffect(() => {
    if (isBlocked) {
      setReadyCount(0);
      return;
    }

    if (currentPanelKey === null) {
      return;
    }

    let isDisposed = false;

    const cancelDeferredReadyState = scheduleDeferredHomePanelsCallback(() => {
      if (isDisposed) {
        return;
      }

      setReadyCount((currentReadyCount) => {
        if (currentReadyCount > readyCount) {
          return currentReadyCount;
        }

        return currentReadyCount + 1;
      });
    });

    return () => {
      isDisposed = true;
      cancelDeferredReadyState();
    };
  }, [currentPanelKey, isBlocked, readyCount]);

  return panelKeys.map((_, index) => index < readyCount) as {
    [TIndex in keyof TPanelKeys]: boolean;
  };
};

export const useHomeScreenDeferredPanelGroup = <const TPanelKeys extends readonly string[]>(
  panelKeys: TPanelKeys,
  isBlocked: boolean,
): { [TIndex in keyof TPanelKeys]: boolean } => {
  const [arePanelsReady, setArePanelsReady] = useState(false);
  const panelKeySignature = panelKeys.join('\u0000');

  useEffect(() => {
    if (isBlocked || panelKeys.length === 0) {
      setArePanelsReady(false);
      return;
    }

    setArePanelsReady(false);

    let isDisposed = false;

    const cancelDeferredReadyState = scheduleDeferredHomePanelsCallback(() => {
      if (isDisposed) {
        return;
      }

      setArePanelsReady(true);
    });

    return () => {
      isDisposed = true;
      cancelDeferredReadyState();
    };
  }, [isBlocked, panelKeySignature, panelKeys.length]);

  return panelKeys.map(() => arePanelsReady) as {
    [TIndex in keyof TPanelKeys]: boolean;
  };
};

export const useHomeScreenDeferredPanels = (
  panelKey: string,
  isBlocked: boolean,
): boolean => {
  const [arePanelsReady, setArePanelsReady] = useState(false);

  useEffect(() => {
    if (isBlocked) {
      setArePanelsReady(false);
      return;
    }

    setArePanelsReady(false);

    let isDisposed = false;

    const settleReadyState = (): void => {
      if (isDisposed) {
        return;
      }

      setArePanelsReady(true);
    };

    const cancelDeferredReadyState = scheduleDeferredHomePanelsCallback(
      settleReadyState,
    );

    return () => {
      isDisposed = true;
      cancelDeferredReadyState();
    };
  }, [isBlocked, panelKey]);

  return arePanelsReady;
};

import {
  getLocalizedKangurMetadataBadgeName,
  KANGUR_BADGES,
} from '@kangur/core';
import { useMemo } from 'react';

import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileHomeProgressSnapshot } from './KangurMobileHomeProgressSnapshotContext';

export type KangurMobileHomeBadgeItem = {
  emoji: string;
  id: string;
  name: string;
};

type UseKangurMobileHomeBadgesResult = {
  recentBadges: KangurMobileHomeBadgeItem[];
  remainingBadges: number;
  totalBadges: number;
  unlockedBadges: number;
};

const HOME_BADGE_RECENT_LIMIT = 3;

let badgeById: Map<string, { id: string; emoji: string; name: string }> | null = null;

const getBadgeById = () => {
  if (!badgeById) {
    badgeById = new Map(KANGUR_BADGES.map((badge) => [badge.id, badge]));
  }
  return badgeById;
};

export const useKangurMobileHomeBadges =
  (): UseKangurMobileHomeBadgesResult => {
    const { locale } = useKangurMobileI18n();
    const progress = useKangurMobileHomeProgressSnapshot();

    return useMemo(() => {
      const badges = getBadgeById();

      const unlockedBadgeIds = Array.from(
        new Set(progress.badges.filter((badgeId) => badges.has(badgeId))),
      );
      const recentBadges = unlockedBadgeIds
        .slice(-HOME_BADGE_RECENT_LIMIT)
        .reverse()
        .map((badgeId) => {
          const badge = badges.get(badgeId);

          if (!badge) {
            return null;
          }

          return {
            emoji: badge.emoji,
            id: badge.id,
            name: getLocalizedKangurMetadataBadgeName(
              badge.id,
              badge.name,
              locale,
            ),
          };
        })
        .filter((badge): badge is KangurMobileHomeBadgeItem => badge !== null);
      const totalBadges = KANGUR_BADGES.length;
      const unlockedBadges = unlockedBadgeIds.length;

      return {
        recentBadges,
        remainingBadges: Math.max(0, totalBadges - unlockedBadges),
        totalBadges,
        unlockedBadges,
      };
    }, [locale, progress]);
  };

import type { KangurDuelLobbyEntry } from '@kangur/contracts/kangur-duels';
import { useQuery } from '@tanstack/react-query';
