      try {
        const response = await apiClient.createDuel(
          {
            mode: 'challenge',
            visibility: 'private',
            opponentLearnerId,
            operation: MOBILE_DUEL_DEFAULT_OPERATION,
            difficulty: MOBILE_DUEL_DEFAULT_DIFFICULTY,
            questionCount: MOBILE_DUEL_DEFAULT_QUESTION_COUNT,
            timePerQuestionSec: MOBILE_DUEL_DEFAULT_TIME_PER_QUESTION_SEC,
          },
          { cache: 'no-store' },
        );

        await queryClient.invalidateQueries({ queryKey: rematchesQueryKey });
        return response.session.id;
      } catch (error) {
        setActionError(
          resolveMobileDuelErrorMessage({
            error,
            copy,
            fallback: {
              de: 'Der private Rückkampf konnte nicht erstellt werden.',
              en: 'Could not create the private rematch.',
              pl: 'Nie udało się utworzyć prywatnego rewanżu.',
            },
            unauthorized: {
              de: 'Melde dich an, um ein privates Rückspiel zu senden.',
              en: 'Sign in to send a private rematch.',
              pl: 'Zaloguj się, aby wysłać prywatny rewanż.',
            },
          }) ?? copy({
            de: 'Der private Rückkampf konnte nicht erstellt werden.',
            en: 'Could not create the private rematch.',
            pl: 'Nie udało się utworzyć prywatnego rewanżu.',
          }),
        );
        return null;
      } finally {
        setIsActionPending(false);
      }
    },
    error: resolveMobileDuelErrorMessage({
      error: rematchesQuery.error,
      copy,
      fallback: {
        de: 'Die letzten Rivalen konnten nicht geladen werden.',
        en: 'Could not load recent opponents.',
        pl: 'Nie udało się pobrać ostatnich rywali.',
      },
      unauthorized: {
        de: 'Melde dich an, um letzte Rivalen zu laden.',
        en: 'Sign in to load recent opponents.',
        pl: 'Zaloguj się, aby pobrać ostatnich rywali.',
      },
    }),
    isActionPending,
    isAuthenticated,
    isLoading: isRestoringAuth || (isQueryEnabled && rematchesQuery.isLoading),
    isRestoringAuth,
    opponents,
    refresh: async () => {
      if (!isQueryEnabled) {
        return;
      }

      await rematchesQuery.refetch();
    },
  };
};

import type { KangurDuelLobbyEntry, KangurDuelStatus } from '@kangur/contracts/kangur-duels';
import { useQuery } from '@tanstack/react-query';
import { useMemo } from 'react';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import {
  buildKangurMobileHomeDuelLobbyQueryKey,
  MOBILE_HOME_DUEL_LOBBY_POLL_MS,
  MOBILE_HOME_DUEL_LOBBY_QUERY_LIMIT,
} from './homeDuelLobbyQuery';

const MOBILE_HOME_DUELS_SPOTLIGHT_LIMIT = 4;

type UseKangurMobileHomeDuelsSpotlightResult = {
  entries: KangurDuelLobbyEntry[];
  error: string | null;
  isLoading: boolean;
  refresh: () => Promise<void>;
};

type UseKangurMobileHomeDuelsSpotlightOptions = {
  enabled?: boolean;
};

const DUEL_SPOTLIGHT_STATUS_PRIORITY: Record<KangurDuelStatus, number> = {
  aborted: 5,
  completed: 4,
  created: 3,
  in_progress: 0,
  ready: 1,
  waiting: 2,
};

const toSpotlightErrorMessage = (
  error: unknown,
  copy: ReturnType<typeof useKangurMobileI18n>['copy'],
): string | null => {
  if (!error) {
    return null;
  }

  if (!(error instanceof Error)) {
    return copy({
      de: 'Aktive Duelle aus der Lobby konnten nicht geladen werden.',
      en: 'Could not load active duels from the lobby.',
      pl: 'Nie udało się pobrać aktywnych pojedynków z lobby.',
    });
  }

  const message = error.message.trim();
  if (!message) {
    return copy({
      de: 'Aktive Duelle aus der Lobby konnten nicht geladen werden.',
      en: 'Could not load active duels from the lobby.',
      pl: 'Nie udało się pobrać aktywnych pojedynków z lobby.',
    });
  }

  const normalized = message.toLowerCase();
  if (normalized === 'failed to fetch' || normalized.includes('networkerror')) {
    return copy({
      de: 'Aktive Duelle aus der Lobby konnten nicht geladen werden.',
      en: 'Could not load active duels from the lobby.',
      pl: 'Nie udało się pobrać aktywnych pojedynków z lobby.',
    });
  }

  return message;
};

const isSpotlightEntry = (entry: KangurDuelLobbyEntry): boolean =>
  entry.visibility === 'public' &&
  (entry.status === 'waiting' ||
    entry.status === 'ready' ||
    entry.status === 'in_progress');

export const useKangurMobileHomeDuelsSpotlight = ({
  enabled = true,
}: UseKangurMobileHomeDuelsSpotlightOptions = {}): UseKangurMobileHomeDuelsSpotlightResult => {
  const { copy } = useKangurMobileI18n();
  const { apiBaseUrl, apiClient } = useKangurMobileRuntime();
  const { session } = useKangurMobileAuth();
  const learnerIdentity =
    session.user?.activeLearner?.id ??
    session.user?.email ??
    session.user?.id ??
    'guest';

  const spotlightQuery = useQuery({
    enabled,
    queryKey: buildKangurMobileHomeDuelLobbyQueryKey(
      apiBaseUrl,
      learnerIdentity,
      'public',
    ),
    queryFn: async () =>
      apiClient.listDuelLobby(
        {
          limit: MOBILE_HOME_DUEL_LOBBY_QUERY_LIMIT,
          visibility: 'public',
        },
        { cache: 'no-store' },
      ),
    refetchInterval: MOBILE_HOME_DUEL_LOBBY_POLL_MS,
    staleTime: 10_000,
  });

  const entries = useMemo(
    () =>
      (spotlightQuery.data?.entries ?? [])
        .filter((entry) => isSpotlightEntry(entry))
        .sort((left, right) => {
          const statusPriority =
            DUEL_SPOTLIGHT_STATUS_PRIORITY[left.status] -
            DUEL_SPOTLIGHT_STATUS_PRIORITY[right.status];

          if (statusPriority !== 0) {
            return statusPriority;
          }

          return Date.parse(right.updatedAt) - Date.parse(left.updatedAt);
        })
        .slice(0, MOBILE_HOME_DUELS_SPOTLIGHT_LIMIT),
    [spotlightQuery.data?.entries],
  );

  return {
    entries,
    error: toSpotlightErrorMessage(spotlightQuery.error, copy),
    isLoading: enabled && spotlightQuery.isLoading,
    refresh: async () => {
      if (!enabled) {
        return;
      }

      await spotlightQuery.refetch();
    },
  };
};

