        <LinkButton
          href={resultsRoute}
          label={copy({
            de: 'Vollständigen Verlauf öffnen',
            en: 'Open full history',
            pl: 'Otwórz pełną historię',
          })}
          stretch
          style={{ borderRadius: 16 }}
          verticalPadding={12}
        />

        <LinkButton
          href={createKangurPlanHref()}
          label={copy({
            de: 'Tagesplan öffnen',
            en: 'Open daily plan',
            pl: 'Otwórz plan dnia',
          })}
          stretch
          style={{ borderRadius: 16 }}
          verticalPadding={12}
        />
      </View>
    </Card>
  );
}

